import * as fs from 'fs';
import * as path from 'path';

import { appLogger } from '@main/logging/logger';
import { DatabaseService } from '@main/services/data/database.service';
import { assertPathWithinRoot } from '@main/utils/path-security.util';
import { createIpcHandler } from '@main/utils/ipc-wrapper.util';
import { ipcMain, shell } from 'electron';


interface GalleryItem {
    name: string
    path: string
    url: string
    mtime: number
    type: 'image' | 'video'
    metadata?: {
        prompt?: string
        negative_prompt?: string
        seed?: number
        steps?: number
        cfg_scale?: number
        width?: number
        height?: number
        model?: string
        created_at?: number
    }
}

export function registerGalleryIpc(galleryPath: string, databaseService?: DatabaseService) {
    const galleryRoot = path.resolve(galleryPath);
    const resolveGalleryPath = (inputPath: string) => assertPathWithinRoot(inputPath, galleryRoot, 'gallery');

    // Ensure gallery exists
    if (!fs.existsSync(galleryRoot)) {
        try {
            fs.mkdirSync(galleryRoot, { recursive: true });
        } catch (e) {
            appLogger.error('Gallery', `Failed to create gallery path: ${e}`);
        }
    }

    ipcMain.handle('gallery:list', createIpcHandler('gallery:list', async () => {
        try {
            const results: GalleryItem[] = [];
            const subdirs = ['images', 'videos'];
            // Fetch metadata from DB if available
            interface GalleryItemMetadata {
                path: string;
                prompt?: string;
                negative_prompt?: string;
                seed?: number;
                steps?: number;
                cfg_scale?: number;
                width?: number;
                height?: number;
                model?: string;
                created_at?: number;
            }
            
            const metadataMap: Record<string, GalleryItemMetadata> = {};
            if (databaseService) {
                try {
                    const dbResults = await databaseService.query<GalleryItemMetadata>('SELECT * FROM gallery_items');
                    dbResults.rows.forEach((row) => {
                        metadataMap[row.path] = row;
                    });
                } catch (e) {
                    appLogger.error('Gallery', `Failed to fetch gallery metadata: ${e}`);
                }
            }

            for (const sub of subdirs) {
                const subPath = path.join(galleryRoot, sub);
                if (!fs.existsSync(subPath)) { continue; }

                const files = await fs.promises.readdir(subPath);
                for (const f of files) {
                    if (/\.(png|jpg|jpeg|webp|gif|mp4|webm|mov)$/i.test(f)) {
                        const fullPath = path.join(subPath, f);
                        const resolvedPath = resolveGalleryPath(fullPath);
                        const stats = fs.statSync(fullPath);
                        results.push({
                            name: f,
                            path: resolvedPath,
                            url: `safe-file://${resolvedPath.replace(/\\/g, '/')}`,
                            mtime: stats.mtime.getTime(),
                            type: sub === 'images' ? 'image' : 'video',
                            metadata: metadataMap[f]
                        });
                    }
                }
            }

            return results.sort((a, b) => b.mtime - a.mtime); // Newest first
        } catch (error) {
            appLogger.error('Gallery', `Gallery List Error: ${error}`);
            return [];
        }
    }));

    ipcMain.handle('gallery:delete', createIpcHandler('gallery:delete', async (_event, filePath: string) => {
        try {
            const safePath = resolveGalleryPath(filePath);
            await fs.promises.unlink(safePath);
            return true;
        } catch (error) {
            appLogger.error('Gallery', `Gallery Delete Error: ${error}`);
            return false;
        }
    }));

    ipcMain.handle('gallery:open', createIpcHandler('gallery:open', async (_event, filePath: string) => {
        try {
            const safePath = resolveGalleryPath(filePath);
            await shell.openPath(safePath);
            return true;
        } catch (error) {
            appLogger.error('Gallery', `Gallery Open Error: ${error}`);
            return false;
        }
    }));

    ipcMain.handle('gallery:reveal', createIpcHandler('gallery:reveal', async (_event, filePath: string) => {
        try {
            const safePath = resolveGalleryPath(filePath);
            shell.showItemInFolder(safePath);
            return true;
        } catch (error) {
            appLogger.error('Gallery', `Gallery Reveal Error: ${error}`);
            return false;
        }
    }));
}

import { appLogger } from '@main/logging/logger';
import { McpMarketplaceService } from '@main/services/mcp/mcp-marketplace.service';
import { McpPluginService } from '@main/services/mcp/mcp-plugin.service';
import { SettingsService } from '@main/services/system/settings.service';
import { MCPServerConfig } from '@shared/types/settings';
import { ipcMain } from 'electron';

/**
 * IPC handlers for MCP Marketplace operations
 */
export function registerMcpMarketplaceHandlers(
    marketplaceService: McpMarketplaceService,
    settingsService: SettingsService,
    mcpPluginService: McpPluginService
) {
    /**
     * List all available servers from marketplace
     */
    ipcMain.handle('mcp:marketplace:list', async () => {
        try {
            const servers = await marketplaceService.listServers();
            return { success: true, servers };
        } catch (error) {
            appLogger.error('MCP Marketplace', `Failed to list servers: ${error}`);
            return { success: false, error: error instanceof Error ? error.message : String(error) };
        }
    });

    /**
     * Search marketplace servers
     */
    ipcMain.handle('mcp:marketplace:search', async (_event, query: string) => {
        try {
            const servers = await marketplaceService.searchServers(query);
            return { success: true, servers };
        } catch (error) {
            appLogger.error('MCP Marketplace', `Failed to search servers: ${error}`);
            return { success: false, error: error instanceof Error ? error.message : String(error) };
        }
    });

    /**
     * Filter servers by category
     */
    ipcMain.handle('mcp:marketplace:filter', async (_event, category: string) => {
        try {
            const servers = await marketplaceService.filterByCategory(category);
            return { success: true, servers };
        } catch (error) {
            appLogger.error('MCP Marketplace', `Failed to filter servers: ${error}`);
            return { success: false, error: error instanceof Error ? error.message : String(error) };
        }
    });

    /**
     * Get all categories
     */
    ipcMain.handle('mcp:marketplace:categories', async () => {
        try {
            const categories = await marketplaceService.getCategories();
            return { success: true, categories };
        } catch (error) {
            appLogger.error('MCP Marketplace', `Failed to get categories: ${error}`);
            return { success: false, error: error instanceof Error ? error.message : String(error) };
        }
    });

    /**
     * Install an MCP server from marketplace
     */
    ipcMain.handle('mcp:marketplace:install', async (_event, serverId: string) => {
        try {
            const servers = await marketplaceService.listServers();
            const server = servers.find(s => s.id === serverId);

            if (!server) {
                return { success: false, error: 'Server not found in marketplace' };
            }

            // Parse command into command and args
            const cmdParts = server.command?.split(' ') || [];
            const command = cmdParts[0] || '';
            const args = cmdParts.slice(1);

            // Create server config
            const serverConfig: MCPServerConfig = {
                id: server.id,
                name: server.name,
                command,
                args,
                description: server.description,
                enabled: false, // Default disabled, user must enable
                category: server.categories?.[0],
                publisher: server.publisher,
                version: server.version,
                isOfficial: server.isOfficial
            };

            // Add to settings
            const settings = settingsService.getSettings();
            const existing = settings.mcpUserServers || [];

            // Check if already installed
            if (existing.some(s => s.id === serverId)) {
                return { success: false, error: 'Server already installed' };
            }

            await settingsService.saveSettings({
                mcpUserServers: [...existing, serverConfig]
            });

            appLogger.info('MCP Marketplace', `Installed server: ${server.name}`);
            return { success: true };
        } catch (error) {
            appLogger.error('MCP Marketplace', `Failed to install server: ${error}`);
            return { success: false, error: error instanceof Error ? error.message : String(error) };
        }
    });

    /**
     * Uninstall an MCP server
     */
    ipcMain.handle('mcp:marketplace:uninstall', async (_event, serverId: string) => {
        try {
            const settings = settingsService.getSettings();
            const existing = settings.mcpUserServers || [];

            const filtered = existing.filter(s => s.id !== serverId);

            if (filtered.length === existing.length) {
                return { success: false, error: 'Server not found' };
            }

            await settingsService.saveSettings({
                mcpUserServers: filtered
            });

            appLogger.info('MCP Marketplace', `Uninstalled server: ${serverId}`);
            return { success: true };
        } catch (error) {
            appLogger.error('MCP Marketplace', `Failed to uninstall server: ${error}`);
            return { success: false, error: error instanceof Error ? error.message : String(error) };
        }
    });

    /**
     * Get list of installed servers (includes both internal built-in tools and user-installed marketplace servers)
     */
    ipcMain.handle('mcp:marketplace:installed', async () => {
        try {
            const settings = settingsService.getSettings();
            const userServers = settings.mcpUserServers || [];

            // Get internal built-in plugins
            const internalPlugins = await mcpPluginService.listPlugins();

            // Convert core plugins to MCPServerConfig format
            const internalServers: MCPServerConfig[] = internalPlugins
                .filter(p => p.source === 'core') // Only include core/built-in plugins
                .map(p => ({
                    id: p.name,
                    name: p.name,
                    command: 'internal',
                    args: [],
                    description: p.description,
                    enabled: true, // Core tools are always enabled
                    tools: p.actions.map(a => ({ name: a.name, description: a.description || '' })),
                    category: 'Internal',
                    isOfficial: true,
                    version: '1.0.0'
                }));

            // Merge internal and user servers
            const allServers = [...internalServers, ...userServers];

            return { success: true, servers: allServers };
        } catch (error) {
            appLogger.error('MCP Marketplace', `Failed to get installed servers: ${error}`);
            return { success: false, error: error instanceof Error ? error.message : String(error) };
        }
    });

    /**
     * Enable/disable an installed MCP server
     */
    ipcMain.handle('mcp:marketplace:toggle', async (_event, serverId: string, enabled: boolean) => {
        try {
            const settings = settingsService.getSettings();
            const existing = settings.mcpUserServers || [];

            const updated = existing.map(s =>
                s.id === serverId ? { ...s, enabled } : s
            );

            await settingsService.saveSettings({
                mcpUserServers: updated
            });

            appLogger.info('MCP Marketplace', `${enabled ? 'Enabled' : 'Disabled'} server: ${serverId}`);
            return { success: true };
        } catch (error) {
            appLogger.error('MCP Marketplace', `Failed to toggle server: ${error}`);
            return { success: false, error: error instanceof Error ? error.message : String(error) };
        }
    });

    /**
     * Refresh marketplace cache
     */
    ipcMain.handle('mcp:marketplace:refresh', async () => {
        try {
            await marketplaceService.refreshCache();
            return { success: true };
        } catch (error) {
            appLogger.error('MCP Marketplace', `Failed to refresh cache: ${error}`);
            return { success: false, error: error instanceof Error ? error.message : String(error) };
        }
    });
}

import * as path from 'path';

import * as dotenv from 'dotenv';
import { app } from 'electron';

dotenv.config();

// Set the application name early
app.setName('Tandem');

import { ApiServerService } from '@main/api/api-server.service';
import { appLogger, LogLevel } from '@main/logging/logger';
import { McpDispatcher } from '@main/mcp/dispatcher';
import { ProxyProcessManager } from '@main/services/proxy/proxy-process.service';
import { registerIpcHandlers } from '@main/startup/ipc';
import { createServices } from '@main/startup/services';
import { ToolExecutor } from '@main/tools/tool-executor';
import { validateEnvironmentVariables } from '@main/utils/env-validator.util';

import { registerLifecycleHandlers } from './startup/lifecycle';
import { preRegisterProtocols, registerProtocols } from './startup/protocols';
import { closeSplashWindow, shouldShowSplashWindow, showSplashWindow } from './startup/splash';
import { createWindow, getMainWindow, setupTray } from './startup/window';

/**
 * Security: Hardening Electron Configuration
 */
app.on('certificate-error', (...args) => {
    const [event, , _url, , , callback] = args;
    event.preventDefault();
    appLogger.warn('Security', `Blocked certificate error for ${_url}`);
    (callback as (allow: boolean) => void)(false);
});

app.commandLine.appendSwitch('js-flags', '--max-old-space-size=8192');
app.commandLine.appendSwitch('disable-site-isolation-trials');

if (process.platform === 'win32') {
    app.setAppUserModelId('com.tandem.app');
}

// Security: Pre-register schemes before app is ready
preRegisterProtocols();

app.whenReady().then(async () => {
    appLogger.setLevel(LogLevel.DEBUG);
    appLogger.installConsoleRedirect();

    appLogger.info('Startup', 'Validating environment variables...');
    validateEnvironmentVariables();

    const shouldShowSplash = shouldShowSplashWindow();
    if (shouldShowSplash) {
        showSplashWindow();
    }

    // Security: Filter allowed roots for file protocol
    const galleryPath = path.join(path.dirname(app.getPath('userData')), 'Gallery');
    const tandemRoaming = path.join(app.getPath('appData'), 'Tandem');
    const allowedFileRoots = new Set([app.getPath('userData'), app.getPath('home'), galleryPath, tandemRoaming]);

    // Register Protocols
    registerProtocols(allowedFileRoots);

    // Initialize Services
    const services = await createServices(allowedFileRoots);

    // Initialize DB & Proxy
    void services.databaseService.initialize().catch(e => appLogger.error('Main', `DB Init Failed: ${e}`));
    void services.proxyService.startEmbeddedProxy().catch(e => appLogger.error('Main', `Proxy Init Failed: ${e}`));

    // Hardened Tool Executor
    const mcpDispatcher = new McpDispatcher(new Set<string>(), services.settingsService, services.mcpPluginService);
    await services.mcpPluginService.initialize();
    await services.mcpMarketplaceService.initialize();

    const toolExecutor = new ToolExecutor({
        fileSystem: services.fileSystemService,
        eventBus: services.eventBusService,
        command: services.commandService,
        web: services.webService,
        screenshot: services.screenshotService,
        system: services.systemService,
        network: services.networkService,
        notification: services.notificationService,
        docker: services.dockerService,
        ssh: services.sshService,
        scanner: services.scannerService,
        embedding: services.embeddingService,
        utility: services.utilityService,
        content: services.contentService,
        file: services.fileManagementService,
        monitor: services.monitoringService,
        clipboard: services.clipboardService,
        git: services.gitService,
        security: services.securityService,
        mcp: mcpDispatcher,
        llm: services.llmService,
        memory: services.memoryService,
        pageSpeed: services.pageSpeedService,
        localImage: services.localImageService
    });

    // Initialize Local API Server
    const proxyProcessManager = services.proxyService['processManager'] as ProxyProcessManager;
    const apiServerService = new ApiServerService({
        port: 42069,
        settingsService: services.settingsService,
        proxyProcessManager: proxyProcessManager,
        toolExecutor: toolExecutor,
        llmService: services.llmService,
        modelRegistry: services.modelRegistryService,
        rateLimitService: services.rateLimitService
    });
    services.apiServerService = apiServerService;

    // Manual registration so Container.dispose() finds it and calls cleanup()
    const { container } = await import('@main/startup/services');
    container.registerInstance('apiServerService', apiServerService);

    await apiServerService.initialize();

    // Register IPC & Lifecycle
    registerIpcHandlers(services, toolExecutor, getMainWindow, allowedFileRoots, mcpDispatcher);
    registerLifecycleHandlers(services.settingsService);

    // Configure Auto-Start
    const settings = services.settingsService.getSettings();
    if (app.isPackaged && settings.window?.startOnStartup !== undefined) {
        const shouldStartHidden = settings.window.workAtBackground ?? false;
        app.setLoginItemSettings({
            openAtLogin: settings.window.startOnStartup,
            openAsHidden: shouldStartHidden,
            path: process.execPath,
            args: shouldStartHidden ? ['--hidden'] : []
        });
    }

    if (settings.window?.workAtBackground) {
        setupTray(services.settingsService);
    }

    // Create Window
    const mainWindow = createWindow(services.settingsService);
    if (shouldShowSplash) {
        mainWindow.once('ready-to-show', () => {
            closeSplashWindow();
        });

        mainWindow.webContents.once('did-fail-load', () => {
            closeSplashWindow();
        });
    }

    // Background Tasks
    const { startOllama } = await import('@main/startup/ollama');
    void startOllama(getMainWindow, false).catch(err => appLogger.error('Main', `Ollama Fail: ${err}`));

    const openedMainWindow = getMainWindow();
    if (openedMainWindow) {
        services.updateService.init(openedMainWindow);
    }
    void services.sentryService.init();

}).catch(e => {
    closeSplashWindow();
    console.error('Critical failure on startup:', e);
    app.exit(1);
});

import * as fs from 'fs';
import * as path from 'path';

import { McpAction, McpResult } from '@main/mcp/types';
import { AuditLogService } from '@main/services/analysis/audit-log.service';
import { MonitoringService } from '@main/services/analysis/monitoring.service';
import { ScannerService } from '@main/services/analysis/scanner.service';
import { DatabaseService } from '@main/services/data/database.service';
import { FileManagementService } from '@main/services/data/file.service';
import { FileSystemService } from '@main/services/data/filesystem.service';
import { ContentService } from '@main/services/external/content.service';
import { UtilityService } from '@main/services/external/utility.service';
import { WebService } from '@main/services/external/web.service';
import { AdvancedMemoryService } from '@main/services/llm/advanced-memory.service';
import { EmbeddingService } from '@main/services/llm/embedding.service';
import { IdeaGeneratorService } from '@main/services/llm/idea-generator.service';
import { ModelCollaborationService } from '@main/services/llm/model-collaboration.service';
import { OllamaService } from '@main/services/llm/ollama.service';
import { DockerService } from '@main/services/project/docker.service';
import { GitService } from '@main/services/project/git.service';
import { SSHService } from '@main/services/project/ssh.service';
import { RateLimitService } from '@main/services/security/rate-limit.service';
import { SecurityService } from '@main/services/security/security.service';
import { CommandService } from '@main/services/system/command.service';
import { NetworkService } from '@main/services/system/network.service';
import { SettingsService } from '@main/services/system/settings.service';
import { SystemService } from '@main/services/system/system.service';
import { ClipboardService } from '@main/services/ui/clipboard.service';
import { NotificationService } from '@main/services/ui/notification.service';
import { ScreenshotService } from '@main/services/ui/screenshot.service';
import { ServiceResponse } from '@shared/types';
import { JsonObject, JsonValue } from '@shared/types/common';
import { getErrorMessage } from '@shared/utils/error.util';

export interface McpDeps {
    web: WebService
    utility: UtilityService
    system: SystemService
    ssh: SSHService
    screenshot: ScreenshotService
    scanner: ScannerService
    notification: NotificationService
    network: NetworkService
    monitoring: MonitoringService
    git: GitService
    security: SecurityService
    settings: SettingsService
    filesystem: FileSystemService
    file: FileManagementService
    embedding: EmbeddingService
    docker: DockerService
    database: DatabaseService
    content: ContentService
    command: CommandService
    clipboard: ClipboardService
    ollama: OllamaService
    advancedMemory: AdvancedMemoryService
    ideaGenerator: IdeaGeneratorService
    modelCollaboration: ModelCollaborationService
    rateLimit: RateLimitService
    auditLog: AuditLogService
}

export type McpHandlerResult = JsonValue | ServiceResponse<JsonValue | void> | void | unknown

export function wrap(
    handler: (args: JsonObject) => McpHandlerResult | Promise<McpHandlerResult>,
    serviceName: string,
    actionName: string,
    auditLog?: AuditLogService
): (args: JsonObject) => Promise<McpResult> {
    return async (args: JsonObject) => {
        const startTime = Date.now();
        try {
            const rawResult = await Promise.resolve(handler(args));
            const result = normalizeResult(rawResult);

            // Audit log successful operation
            if (auditLog) {
                await auditLog.log({
                    action: `mcp:${serviceName}:${actionName}`,
                    category: 'system',
                    success: result.success,
                    details: {
                        serviceName,
                        actionName,
                        duration: Date.now() - startTime,
                        argsKeys: Object.keys(args)
                    },
                    error: result.success ? undefined : result.error
                }).catch(() => { /* Ignore audit log errors */ });
            }

            return result;
        } catch (error) {
            const errorMsg = getErrorMessage(error);

            // Audit log failed operation
            if (auditLog) {
                await auditLog.log({
                    action: `mcp:${serviceName}:${actionName}`,
                    category: 'system',
                    success: false,
                    details: {
                        serviceName,
                        actionName,
                        duration: Date.now() - startTime,
                        argsKeys: Object.keys(args)
                    },
                    error: errorMsg
                }).catch(() => { /* Ignore audit log errors */ });
            }

            return { success: false, error: errorMsg };
        }
    };
}

export function normalizeResult(rawResult: McpHandlerResult): McpResult {
    if (isServiceResponse(rawResult)) {
        return normalizeServiceResponse(rawResult);
    }
    return { success: true, data: (rawResult ?? null) as JsonValue };
}

export function isServiceResponse(result: unknown): result is ServiceResponse<unknown> {
    return !!(result && typeof result === 'object' && 'success' in result);
}

export function normalizeServiceResponse(res: ServiceResponse<unknown>): McpResult {
    if (res.success === false) {
        return { success: false, error: (res.error ?? res.message) ?? 'Unknown error' };
    }
    const data = res.data ?? res.result ?? res.content ?? res;
    return { success: true, data: data as JsonValue };
}

export const buildActions = (
    actions: Array<Omit<McpAction, 'handler'> & { handler: (args: JsonObject) => McpHandlerResult | Promise<McpHandlerResult> }>,
    serviceName?: string,
    auditLog?: AuditLogService
): McpAction[] =>
    actions.map(a => ({ ...a, handler: wrap(a.handler, serviceName ?? 'unknown', a.name, auditLog) }));

export const normalizeTarget = (target: string): string => {
    const trimmed = String(target).trim();
    if (!trimmed) { return ''; }
    try {
        const url = new URL(trimmed.includes('://') ? trimmed : `http://${trimmed}`);
        return url.hostname;
    } catch {
        return trimmed;
    }
};

export const ensureAllowedTarget = (deps: McpDeps, target: string) => {
    const allowed = deps.settings.getSettings().mcpSecurityAllowedHosts ?? [];
    const normalized = normalizeTarget(target);
    if (!normalized) {
        throw new Error('Target is required');
    }
    if (!allowed.includes(normalized)) {
        throw new Error(`Target not allowlisted: ${normalized}`);
    }
    return normalized;
};

/**
 * Validates a file path to prevent path traversal attacks
 * @param basePath - The allowed base directory
 * @param inputPath - The user-provided path
 * @returns The validated absolute path
 * @throws Error if path traversal is detected
 */
export const validatePath = (basePath: string, inputPath: string): string => {
    if (!inputPath || typeof inputPath !== 'string') {
        throw new Error('Path is required and must be a string');
    }

    const resolved = path.resolve(basePath, inputPath);

    // Check for path traversal
    if (!resolved.startsWith(basePath)) {
        throw new Error(`Path traversal detected: ${inputPath}`);
    }

    // Check for symlinks (prevent symlink attacks)
    try {
        const realPath = fs.realpathSync(resolved);
        if (!realPath.startsWith(basePath)) {
            throw new Error(`Symlink traversal detected: ${inputPath}`);
        }
        return realPath;
    } catch (error) {
        // If file doesn't exist yet, that's okay for write operations
        // Just verify the parent directory doesn't escape
        const parentDir = path.dirname(resolved);
        if (!parentDir.startsWith(basePath)) {
            throw new Error(`Path traversal detected in parent directory: ${inputPath}`);
        }
        return resolved;
    }
};

/**
 * Wraps a handler with timeout protection
 * @param handler - The async handler function
 * @param timeoutMs - Timeout in milliseconds (default: 30000)
 * @returns Wrapped handler with timeout
 */
export const withTimeout = <T>(
    handler: () => Promise<T>,
    timeoutMs = 30000
): Promise<T> => {
    return Promise.race([
        handler(),
        new Promise<T>((_, reject) =>
            setTimeout(() => reject(new Error(`Operation timeout after ${timeoutMs}ms`)), timeoutMs)
        )
    ]);
};

/**
 * Validates string parameter with size limit
 * @param value - The value to validate
 * @param maxLength - Maximum allowed length (default: 1MB)
 * @returns The validated string
 */
export const validateString = (value: unknown, maxLength = 1048576): string => {
    if (typeof value !== 'string') {
        throw new Error('Value must be a string');
    }
    if (value.length > maxLength) {
        throw new Error(`String too long (max ${maxLength} characters)`);
    }
    return value;
};

/**
 * Validates number parameter with bounds
 * @param value - The value to validate
 * @param min - Minimum allowed value
 * @param max - Maximum allowed value
 * @returns The validated number
 */
export const validateNumber = (value: unknown, min?: number, max?: number): number => {
    const num = Number(value);
    if (isNaN(num)) {
        throw new Error('Value must be a valid number');
    }
    if (min !== undefined && num < min) {
        throw new Error(`Number must be >= ${min}`);
    }
    if (max !== undefined && num > max) {
        throw new Error(`Number must be <= ${max}`);
    }
    return num;
};

/**
 * Validates URL and ensures it uses safe protocols
 * @param value - The URL to validate
 * @param allowedProtocols - Allowed protocols (default: ['http:', 'https:'])
 * @returns The validated URL string
 */
export const validateUrl = (value: unknown, allowedProtocols = ['http:', 'https:']): string => {
    const urlString = validateString(value, 2000);

    try {
        const parsed = new URL(urlString);
        if (!allowedProtocols.includes(parsed.protocol)) {
            throw new Error(`Only ${allowedProtocols.join(', ')} protocols allowed`);
        }
        return parsed.href;
    } catch (error) {
        if (error instanceof Error && error.message.includes('protocol')) {
            throw error;
        }
        throw new Error(`Invalid URL: ${getErrorMessage(error)}`);
    }
};

/**
 * Validates hostname format
 * @param value - The hostname to validate
 * @returns The validated hostname
 */
export const validateHostname = (value: unknown): string => {
    const hostname = validateString(value, 253);

    // Basic hostname validation (alphanumeric, dots, hyphens)
    if (!/^[a-zA-Z0-9.-]+$/.test(hostname)) {
        throw new Error('Invalid hostname format');
    }

    return hostname;
};

/**
 * Validates command to prevent injection
 * @param value - The command to validate
 * @returns The validated command
 */
export const validateCommand = (value: unknown): string => {
    const cmd = validateString(value, 10000).trim();

    if (!cmd) {
        throw new Error('Command is required');
    }

    // Warn about potentially dangerous characters (but don't block - service layer should use array-based execution)
    const dangerousChars = /[;&|`$(){}[\]<>]/;
    if (dangerousChars.test(cmd)) {
        // This is a warning - the actual protection should be using array-based command execution
        console.warn('[MCP Security] Command contains potentially dangerous characters:', cmd);
    }

    return cmd;
};

/**
 * Wraps a handler with rate limiting protection
 * @param deps - MCP dependencies
 * @param serviceName - The MCP service name (e.g., 'git', 'docker', 'filesystem')
 * @param handler - The async handler function
 * @returns Wrapped handler with rate limiting
 */
export const withRateLimit = <T>(
    deps: McpDeps,
    serviceName: string,
    handler: () => Promise<T>
): Promise<T> => {
    return deps.rateLimit.waitForToken(`mcp:${serviceName}`).then(() => handler());
};

import { buildActions, McpDeps, validateNumber, validateString, withTimeout } from '@main/mcp/server-utils';
import { McpService } from '@main/mcp/types';

/**
 * Validates IP address format (IPv4 only for safety)
 */
const validateIPAddress = (ip: unknown): string => {
    const ipStr = validateString(ip, 45); // Max IPv6 length

    // Only allow public IPv4 addresses
    const ipv4Pattern = /^(\d{1,3}\.){3}\d{1,3}$/;

    if (!ipv4Pattern.test(ipStr)) {
        throw new Error('Invalid IP address format (only IPv4 supported)');
    }

    // Check each octet is valid
    const octets = ipStr.split('.');
    for (const octet of octets) {
        const num = parseInt(octet, 10);
        if (num < 0 || num > 255) {
            throw new Error('Invalid IP address octets');
        }
    }

    // Prevent private/local IPs (SSRF protection)
    const firstOctet = parseInt(octets[0], 10);
    const secondOctet = parseInt(octets[1], 10);

    if (
        firstOctet === 10 || // 10.0.0.0/8
        firstOctet === 127 || // 127.0.0.0/8 (localhost)
        (firstOctet === 172 && secondOctet >= 16 && secondOctet <= 31) || // 172.16.0.0/12
        (firstOctet === 192 && secondOctet === 168) || // 192.168.0.0/16
        firstOctet === 0 || // 0.0.0.0/8
        firstOctet >= 224 // Multicast/reserved
    ) {
        throw new Error('Private/local IP addresses not allowed (SSRF protection)');
    }

    return ipStr;
};

/**
 * Validates timezone format
 */
const validateTimezone = (tz: unknown): string => {
    const timezone = validateString(tz, 100);

    // Basic timezone validation (Area/Location format)
    if (!/^[A-Z][a-zA-Z_]+\/[A-Z][a-zA-Z_]+$/.test(timezone) && timezone !== 'Etc/UTC') {
        throw new Error('Invalid timezone format (use Area/Location, e.g., Europe/London)');
    }

    return timezone;
};

export function buildInternetServers(deps: McpDeps): McpService[] {
    return [
        {
            name: 'weather',
            description: 'Weather information',
            actions: buildActions([
                {
                    name: 'forecast',
                    description: 'Get weather forecast from wttr.in',
                    handler: async ({ location }) => {
                        const loc = location
                            ? encodeURIComponent(validateString(location, 100))
                            : '';
                        const url = `https://wttr.in/${loc}?format=j1`;

                        return await withTimeout(
                            () => deps.web.fetchJson(url),
                            10000
                        );
                    }
                }
            ], 'weather', deps.auditLog)
        },
        {
            name: 'geo',
            description: 'Geolocation utilities',
            actions: buildActions([
                {
                    name: 'ip',
                    description: 'Get IP location info (public IPs only - SSRF protected)',
                    handler: async ({ ip }) => {
                        const target = ip ? validateIPAddress(ip) : 'json';
                        const url = `https://ipapi.co/${target}/json/`;

                        return await withTimeout(
                            () => deps.web.fetchJson(url),
                            10000
                        );
                    }
                }
            ], 'geo', deps.auditLog)
        },
        {
            name: 'news',
            description: 'Tech news headlines',
            actions: buildActions([
                {
                    name: 'hackernews',
                    description: 'Get top HackerNews stories (max 30)',
                    handler: async ({ count }) => {
                        const limit = validateNumber(count ?? 10, 1, 30);

                        const idsRes = await withTimeout(
                            () => deps.web.fetchJson('https://hacker-news.firebaseio.com/v0/topstories.json'),
                            10000
                        );

                        if (!idsRes.success || !Array.isArray(idsRes.data)) {
                            return { success: false, error: 'Failed to fetch top stories' };
                        }

                        const ids = (idsRes.data as unknown as number[]).slice(0, limit);

                        // Fetch stories with limited concurrency
                        const stories = await Promise.all(
                            ids.map(async (id: number) => {
                                const storyRes = await withTimeout(
                                    () => deps.web.fetchJson(`https://hacker-news.firebaseio.com/v0/item/${id}.json`),
                                    5000
                                );
                                return storyRes.data;
                            })
                        );

                        return { success: true, data: stories };
                    }
                }
            ], 'news', deps.auditLog)
        },
        {
            name: 'finance',
            description: 'Crypto and Forex info',
            actions: buildActions([
                {
                    name: 'crypto',
                    description: 'Get simple crypto price (e.g. "bitcoin")',
                    handler: async ({ coin, currency }) => {
                        const c = coin
                            ? validateString(coin, 50).toLowerCase()
                            : 'bitcoin';
                        const vs = currency
                            ? validateString(currency, 10).toLowerCase()
                            : 'usd';

                        // Validate coin/currency format (alphanumeric only)
                        if (!/^[a-z0-9-]+$/.test(c) || !/^[a-z]{3}$/.test(vs)) {
                            throw new Error('Invalid coin or currency format');
                        }

                        const url = `https://api.coingecko.com/api/v3/simple/price?ids=${c}&vs_currencies=${vs}`;

                        return await withTimeout(
                            () => deps.web.fetchJson(url),
                            10000
                        );
                    }
                }
            ], 'finance', deps.auditLog)
        },
        {
            name: 'time',
            description: 'World time information',
            actions: buildActions([
                {
                    name: 'now',
                    description: 'Get current time for a timezone (e.g. "Europe/London")',
                    handler: async ({ timezone }) => {
                        const tz = timezone ? validateTimezone(timezone) : 'Etc/UTC';
                        const url = `https://worldtimeapi.org/api/timezone/${tz}`;

                        return await withTimeout(
                            () => deps.web.fetchJson(url),
                            10000
                        );
                    }
                }
            ], 'time', deps.auditLog)
        }
    ];
}

import { buildActions, ensureAllowedTarget, McpDeps, validateCommand, validateHostname, validateString, withTimeout } from '@main/mcp/server-utils';
import { McpService } from '@main/mcp/types';
import { SSHConnection } from '@main/services/project/ssh.service';

/**
 * Validates SSH connection ID format
 */
const validateConnectionId = (id: unknown): string => {
    const connId = validateString(id, 100);

    if (!connId) {
        throw new Error('Connection ID is required');
    }

    // Only allow alphanumeric and hyphens
    if (!/^[a-zA-Z0-9-]+$/.test(connId)) {
        throw new Error('Invalid connection ID format');
    }

    return connId;
};

/**
 * Validates SSH connection parameters
 */
const validateSSHConnection = (args: unknown): SSHConnection => {
    const conn = args as SSHConnection;

    if (!conn || typeof conn !== 'object') {
        throw new Error('Invalid SSH connection parameters');
    }

    // Validate required fields
    if (!conn.host || typeof conn.host !== 'string') {
        throw new Error('SSH host is required');
    }

    if (!conn.username || typeof conn.username !== 'string') {
        throw new Error('SSH username is required');
    }

    // Validate host format
    validateHostname(conn.host);

    // Validate port if provided
    if (conn.port !== undefined) {
        const port = Number(conn.port);
        if (isNaN(port) || port < 1 || port > 65535) {
            throw new Error('Invalid SSH port (must be 1-65535)');
        }
    }

    // Note: Password/key should be encrypted by the service layer using Electron safeStorage
    // We don't validate them here to avoid logging sensitive data

    return conn;
};

export function buildNetworkServers(deps: McpDeps): McpService[] {
    return [
        {
            name: 'ssh',
            description: 'SSH connections and remote commands (validated)',
            actions: buildActions([
                {
                    name: 'connect',
                    description: 'Open SSH connection with validation',
                    handler: (args) => withTimeout(
                        () => deps.ssh.connect(validateSSHConnection(args)),
                        30000
                    )
                },
                {
                    name: 'execute',
                    description: 'Run remote command with validation (warning: ensure internal service uses array-based execution)',
                    handler: ({ connectionId, command, cwd }) => {
                        const validConnId = validateConnectionId(connectionId);
                        const validCommand = validateCommand(command);
                        const validCwd = cwd ? validateString(cwd, 500) : undefined;

                        return withTimeout(
                            () => deps.ssh.executeCommand(
                                validConnId,
                                validCommand,
                                validCwd ? { cwd: validCwd } : undefined
                            ),
                            60000 // 1 minute timeout for remote commands
                        );
                    }
                },
                {
                    name: 'disconnect',
                    description: 'Close SSH connection',
                    handler: ({ connectionId }) => withTimeout(
                        async () => {
                            await deps.ssh.disconnect(validateConnectionId(connectionId));
                            return { success: true };
                        },
                        10000
                    )
                }
            ], 'ssh', deps.auditLog)
        },
        {
            name: 'network',
            description: 'Network utilities (allowlist-protected)',
            actions: buildActions([
                {
                    name: 'ping',
                    description: 'Ping host (requires allowlist)',
                    handler: ({ host }) => {
                        const allowedHost = ensureAllowedTarget(deps, host as string);

                        return withTimeout(
                            () => deps.network.ping(allowedHost),
                            30000
                        );
                    }
                },
                {
                    name: 'traceroute',
                    description: 'Run traceroute (requires allowlist)',
                    handler: ({ host }) => {
                        const allowedHost = ensureAllowedTarget(deps, host as string);

                        return withTimeout(
                            () => deps.network.traceroute(allowedHost),
                            60000 // Traceroute can take longer
                        );
                    }
                },
                {
                    name: 'whois',
                    description: 'WHOIS lookup (requires allowlist)',
                    handler: ({ domain }) => {
                        const allowedDomain = ensureAllowedTarget(deps, domain as string);

                        return withTimeout(
                            () => deps.network.whois(allowedDomain),
                            30000
                        );
                    }
                }
            ], 'network', deps.auditLog)
        }
    ];
}

/**
 * Time Tracking Service
 * Tracks app online time, coding time, and per-project coding time
 */

import { BaseService } from '@main/services/base.service';
import { DatabaseClientService } from '@main/services/data/database-client.service';
import { v4 as uuidv4 } from 'uuid';

export interface TimeTrackingRecord {
    id: string
    type: 'app_online' | 'coding' | 'project_coding'
    projectId?: string
    startTime: number
    endTime?: number
    durationMs: number
    createdAt: number
    updatedAt: number
}

export interface TimeTrackingStats {
    totalOnlineTime: number // in milliseconds
    totalCodingTime: number // in milliseconds
    projectCodingTime: Record<string, number> // projectId -> milliseconds
}

export class TimeTrackingService extends BaseService {
    private appStartTime: number | null = null;
    private codingStartTime: number | null = null;
    private projectStartTimes: Map<string, number> = new Map();
    private saveInterval: NodeJS.Timeout | null = null;
    private isTracking = false;

    constructor(
        private databaseClient: DatabaseClientService
    ) {
        super('TimeTrackingService');
    }

    async initialize(): Promise<void> {
        // Load any incomplete sessions on startup
        await this.resumeTracking();

        // Start tracking app online time
        this.startAppTracking();

        // Save tracking data every 60 seconds
        this.saveInterval = setInterval(() => {
            this.saveCurrentTracking().catch(err => {
                this.logError('Failed to save current tracking', err);
            });
        }, 60000);
    }

    async cleanup(): Promise<void> {
        // Stop tracking and save final times
        await this.stopAppTracking();
        if (this.saveInterval) {
            clearInterval(this.saveInterval);
            this.saveInterval = null;
        }
    }

    /**
     * Start tracking app online time
     */
    startAppTracking(): void {
        if (this.isTracking) { return; }
        this.isTracking = true;
        this.appStartTime = Date.now();
        this.logInfo('Started app tracking');
    }

    /**
     * Stop tracking app online time and save
     */
    async stopAppTracking(): Promise<void> {
        if (!this.isTracking || !this.appStartTime) { return; }
        const endTime = Date.now();
        const duration = endTime - this.appStartTime;

        await this.recordTime({
            type: 'app_online',
            startTime: this.appStartTime,
            endTime,
            durationMs: duration
        });

        this.appStartTime = null;
        this.isTracking = false;
        this.logInfo('Stopped app tracking');
    }

    /**
     * Start tracking coding time (when a project is active)
     */
    startCodingTracking(projectId?: string): void {
        if (projectId) {
            this.projectStartTimes.set(projectId, Date.now());
        } else {
            this.codingStartTime = Date.now();
        }
    }

    /**
     * Stop tracking coding time for a project
     */
    async stopCodingTracking(projectId?: string): Promise<void> {
        const now = Date.now();

        if (projectId) {
            const startTime = this.projectStartTimes.get(projectId);
            if (startTime) {
                const duration = now - startTime;
                await this.recordTime({
                    type: 'project_coding',
                    projectId,
                    startTime,
                    endTime: now,
                    durationMs: duration
                });
                this.projectStartTimes.delete(projectId);
            }
        } else {
            if (this.codingStartTime) {
                const duration = now - this.codingStartTime;
                await this.recordTime({
                    type: 'coding',
                    startTime: this.codingStartTime,
                    endTime: now,
                    durationMs: duration
                });
                this.codingStartTime = null;
            }
        }
    }

    /**
     * Record a time tracking entry
     */
    private async recordTime(record: Omit<TimeTrackingRecord, 'id' | 'createdAt' | 'updatedAt'>): Promise<void> {
        try {
            const id = uuidv4();
            const now = Date.now();

            await this.databaseClient.executeQuery({
                sql: `
                    INSERT INTO time_tracking (id, type, project_id, start_time, end_time, duration_ms, created_at, updated_at)
                    VALUES (?, ?, ?, ?, ?, ?, ?, ?)
                `,
                params: [
                    id,
                    record.type,
                    record.projectId ?? null,
                    record.startTime,
                    record.endTime ?? null,
                    record.durationMs,
                    now,
                    now
                ]
            });
        } catch (error) {
            this.logError('Failed to record time', error);
        }
    }

    /**
     * Save current tracking state (called periodically)
     */
    private async saveCurrentTracking(): Promise<void> {
        // Save app online time if tracking
        if (this.isTracking && this.appStartTime) {
            // We don't want to save incomplete sessions here, just continue tracking
            // Complete sessions are saved when stopAppTracking is called
        }
    }

    /**
     * Resume tracking from incomplete sessions (on app startup)
     */
    private async resumeTracking(): Promise<void> {
        // On startup, we assume the app was closed, so we don't resume incomplete sessions
        // This is by design - we only track active sessions
    }

    /**
     * Get total statistics
     */
    async getTimeStats(): Promise<TimeTrackingStats> {
        try {
            const appOnlineTotal = await this.getTotalTimeByType('app_online');
            const codingTotal = await this.getTotalTimeByType('coding');
            const projectCodingTime = await this.getProjectCodingStats();

            // Add current active tracking time
            const now = Date.now();
            const currentAppTime = (this.isTracking && this.appStartTime)
                ? now - this.appStartTime
                : 0;
            const currentCodingTime = this.codingStartTime
                ? now - this.codingStartTime
                : 0;

            // Add current project times from active sessions
            for (const [projectId, startTime] of this.projectStartTimes.entries()) {
                projectCodingTime[projectId] = (projectCodingTime[projectId] ?? 0) + (now - startTime);
            }

            return {
                totalOnlineTime: appOnlineTotal + currentAppTime,
                totalCodingTime: codingTotal + currentCodingTime,
                projectCodingTime
            };
        } catch (error) {
            this.logError('Failed to get time stats', error as Error);
            return {
                totalOnlineTime: 0,
                totalCodingTime: 0,
                projectCodingTime: {}
            };
        }
    }

    /**
     * Helper to get total time by tracking type
     */
    private async getTotalTimeByType(type: string): Promise<number> {
        const response = await this.databaseClient.executeQuery({
            sql: `SELECT COALESCE(SUM(duration_ms), 0) as total FROM time_tracking WHERE type = ?`,
            params: [type]
        });
        return (response.rows[0]?.total as number) ?? 0;
    }

    /**
     * Helper to get per-project coding statistics
     */
    private async getProjectCodingStats(): Promise<Record<string, number>> {
        const response = await this.databaseClient.executeQuery({
            sql: `SELECT project_id, COALESCE(SUM(duration_ms), 0) as total FROM time_tracking WHERE type = 'project_coding' AND project_id IS NOT NULL GROUP BY project_id`
        });

        const projectCodingTime: Record<string, number> = {};
        const rows = response.rows ?? [];
        for (const row of rows) {
            if (row.project_id) {
                projectCodingTime[String(row.project_id)] = Number(row.total);
            }
        }
        return projectCodingTime;
    }
}

import { watch } from 'fs';
import { createWriteStream } from 'fs';
import * as fs from 'fs/promises';
import * as https from 'https';
import * as path from 'path';

import { appLogger } from '@main/logging/logger';
import { JsonObject } from '@shared/types/common';
import { AISystemType } from '@shared/types/file-diff';
import { ServiceResponse } from '@shared/types/index';
import { getErrorMessage } from '@shared/utils/error.util';

import type { FileChangeTracker } from './file-change-tracker.service';

export class FileSystemService {
    private allowedRoots: string[] = [];
    private fileChangeTracker?: FileChangeTracker;

    constructor(allowedRoots?: string[], fileChangeTracker?: FileChangeTracker) {
        if (allowedRoots) {
            this.allowedRoots = allowedRoots.map(r => path.resolve(r));
        }
        this.fileChangeTracker = fileChangeTracker;
    }

    setFileChangeTracker(tracker: FileChangeTracker) {
        this.fileChangeTracker = tracker;
    }

    updateAllowedRoots(allowedRoots: string[]) {
        this.allowedRoots = allowedRoots.map(r => path.resolve(r));
    }

    private isPathAllowed(filePath: string): boolean {
        const absolutePath = path.resolve(filePath);
        return this.allowedRoots.some(root => {
            if (absolutePath === root) { return true; }
            return absolutePath.startsWith(root + path.sep);
        });
    }

    private validatePath(filePath: string) {
        if (!this.isPathAllowed(filePath)) {
            throw new Error(`Access denied: Path is outside allowed directories. (${filePath})`);
        }
    }



    private ignorePatterns: string[] = ['node_modules', '.git', 'dist', 'build', '.tandem', '.DS_Store'];

    updateIgnorePatterns(patterns: string[]) {
        this.ignorePatterns = [...new Set([...this.ignorePatterns, ...patterns])];
    }

    private shouldIgnore(filePath: string): boolean {
        // Simple string inclusion checker for now, should be replaced with proper minimatch/glob later
        return this.ignorePatterns.some(pattern => filePath.includes(path.sep + pattern) || filePath.endsWith(path.sep + pattern));
    }

    // --- Core Operations ---

    async readFile(filePath: string): Promise<ServiceResponse<string>> {
        try {
            this.validatePath(filePath);
            const absolutePath = path.resolve(filePath);
            const stats = await fs.stat(absolutePath);

            // 10MB limit
            if (stats.size > 10 * 1024 * 1024) {
                return { success: false, error: 'File too large (>10MB)' };
            }

            // Simple binary check: read first 1024 bytes and look for null bytes
            const handle = await fs.open(absolutePath, 'r');
            const buffer = Buffer.alloc(Math.min(stats.size, 1024));
            await handle.read(buffer, 0, buffer.length, 0);
            await handle.close();

            // If it contains a null byte, effectively considered binary
            if (buffer.includes(0)) {
                return { success: false, error: 'File is binary' };
            }

            const content = await fs.readFile(absolutePath, 'utf-8');
            return { success: true, data: content };
        } catch (error) {
            return { success: false, error: getErrorMessage(error as Error) };
        }
    }

    async readImage(filePath: string): Promise<ServiceResponse<string>> {
        try {
            this.validatePath(filePath);
            const absolutePath = path.resolve(filePath);
            const stats = await fs.stat(absolutePath);
            if (stats.size > 20 * 1024 * 1024) { // 20MB limit for images
                return { success: false, error: 'Image too large (>20MB)' };
            }
            const buffer = await fs.readFile(absolutePath);
            const base64 = buffer.toString('base64');

            // Determine mime type from extension
            const ext = path.extname(absolutePath).toLowerCase();
            let mime = 'image/jpeg';
            if (ext === '.png') { mime = 'image/png'; }
            if (ext === '.gif') { mime = 'image/gif'; }
            if (ext === '.webp') { mime = 'image/webp'; }
            if (ext === '.svg') { mime = 'image/svg+xml'; }

            return { success: true, data: `data:${mime};base64,${base64}` };
        } catch (error) {
            return { success: false, error: getErrorMessage(error as Error) };
        }
    }

    async isBinaryFile(filePath: string): Promise<boolean> {
        try {
            this.validatePath(filePath);
            const absolutePath = path.resolve(filePath);
            const stats = await fs.stat(absolutePath);
            if (stats.size === 0) { return false; }

            const handle = await fs.open(absolutePath, 'r');
            const buffer = Buffer.alloc(Math.min(stats.size, 1024));
            await handle.read(buffer, 0, buffer.length, 0);
            await handle.close();

            return buffer.includes(0);
        } catch {
            return false;
        }
    }

    async writeFile(filePath: string, content: string): Promise<ServiceResponse> {
        try {
            this.validatePath(filePath);
            const absolutePath = path.resolve(filePath);
            const dir = path.dirname(absolutePath);
            await fs.mkdir(dir, { recursive: true });
            await fs.writeFile(absolutePath, content, 'utf-8');
            return { success: true };
        } catch (error) {
            return { success: false, error: getErrorMessage(error as Error) };
        }
    }

    /**
     * Write file with AI change tracking
     */
    async writeFileWithTracking(
        filePath: string,
        content: string,
        context: {
            aiSystem: AISystemType
            chatSessionId?: string
            changeReason?: string
            metadata?: JsonObject
        }
    ): Promise<ServiceResponse> {
        try {
            this.validatePath(filePath);
            const absolutePath = path.resolve(filePath);

            // Get current content if file exists
            let beforeContent = '';
            try {
                beforeContent = await fs.readFile(absolutePath, 'utf-8');
            } catch {
                // File doesn't exist, beforeContent stays empty
            }

            // Write the new content
            const dir = path.dirname(absolutePath);
            await fs.mkdir(dir, { recursive: true });
            await fs.writeFile(absolutePath, content, 'utf-8');

            // Track the change if tracker is available
            if (this.fileChangeTracker) {
                await this.fileChangeTracker.trackFileChange(absolutePath, beforeContent, content, context);
            }

            return { success: true };
        } catch (error) {
            return { success: false, error: getErrorMessage(error as Error) };
        }
    }

    async listDirectory(dirPath: string): Promise<ServiceResponse<Array<{ name: string; isDirectory: boolean; size?: number; modified?: string }>>> {
        try {
            this.validatePath(dirPath);
            const absolutePath = path.resolve(dirPath);
            const entries = await fs.readdir(absolutePath, { withFileTypes: true });

            const filteredEntries = entries.filter(entry => !this.shouldIgnore(path.join(absolutePath, entry.name)));

            const files = await Promise.all(
                filteredEntries.map(async (entry) => {
                    const entryPath = path.join(absolutePath, entry.name);
                    let size: number | undefined;
                    let modified: string | undefined;
                    try {
                        const stats = await fs.stat(entryPath);
                        size = stats.size;
                        modified = stats.mtime.toISOString();
                    } catch (e) {
                        appLogger.warn('filesystem.service', `Failed to stat ${entryPath}: ${getErrorMessage(e as Error)}`);
                    }
                    return {
                        name: entry.name,
                        isDirectory: entry.isDirectory(),
                        size,
                        modified
                    };
                })
            );
            return { success: true, data: files };
        } catch (error) {
            return { success: false, error: getErrorMessage(error as Error) };
        }
    }

    async createDirectory(dirPath: string): Promise<ServiceResponse> {
        try {
            this.validatePath(dirPath);
            const absolutePath = path.resolve(dirPath);
            await fs.mkdir(absolutePath, { recursive: true });
            return { success: true };
        } catch (error) {
            return { success: false, error: getErrorMessage(error as Error) };
        }
    }

    async deleteFile(filePath: string): Promise<ServiceResponse> {
        try {
            this.validatePath(filePath);
            await fs.unlink(path.resolve(filePath));
            return { success: true };
        } catch (error) {
            return { success: false, error: getErrorMessage(error as Error) };
        }
    }

    async deleteDirectory(dirPath: string): Promise<ServiceResponse> {
        try {
            this.validatePath(dirPath);
            await fs.rm(path.resolve(dirPath), { recursive: true, force: true });
            return { success: true };
        } catch (error) {
            return { success: false, error: getErrorMessage(error as Error) };
        }
    }

    async fileExists(filePath: string): Promise<{ exists: boolean }> {
        try {
            await fs.access(path.resolve(filePath));
            return { exists: true };
        } catch {
            return { exists: false };
        }
    }

    async getFileInfo(filePath: string): Promise<ServiceResponse<{ path: string; size: number; isDirectory: boolean; isFile: boolean; created: string; modified: string; accessed: string }>> {
        try {
            this.validatePath(filePath);
            const absolutePath = path.resolve(filePath);
            const stats = await fs.stat(absolutePath);
            return {
                success: true,
                data: {
                    path: absolutePath,
                    size: stats.size,
                    isDirectory: stats.isDirectory(),
                    isFile: stats.isFile(),
                    created: stats.birthtime.toISOString(),
                    modified: stats.mtime.toISOString(),
                    accessed: stats.atime.toISOString()
                }
            };
        } catch (error) {
            return { success: false, error: getErrorMessage(error as Error) };
        }
    }

    async copyFile(source: string, destination: string): Promise<ServiceResponse> {
        try {
            this.validatePath(source);
            this.validatePath(destination);
            const srcPath = path.resolve(source);
            const destPath = path.resolve(destination);
            await fs.copyFile(srcPath, destPath);
            return { success: true };
        } catch (error) {
            return { success: false, error: getErrorMessage(error as Error) };
        }
    }

    async moveFile(source: string, destination: string): Promise<ServiceResponse> {
        try {
            this.validatePath(source);
            this.validatePath(destination);
            const srcPath = path.resolve(source);
            const destPath = path.resolve(destination);
            await fs.mkdir(path.dirname(destPath), { recursive: true });
            await fs.rename(srcPath, destPath);
            return { success: true };
        } catch (error) {
            return { success: false, error: getErrorMessage(error as Error) };
        }
    }

    // --- Extended Operations (from FileManagementService) ---

    async extractStrings(filePath: string, minLength: number = 4): Promise<ServiceResponse<{ strings: string[] }>> {
        try {
            const buffer = await fs.readFile(path.resolve(filePath));
            const strings: string[] = [];
            let current = "";
            for (let i = 0; i < buffer.length; i++) {
                const char = buffer[i];
                if (char >= 32 && char <= 126) {
                    current += String.fromCharCode(char);
                } else {
                    if (current.length >= minLength) { strings.push(current); }
                    current = "";
                }
            }
            return { success: true, data: { strings } };
        } catch (e) {
            return { success: false, error: getErrorMessage(e as Error) };
        }
    }

    async syncNote(title: string, content: string, dir: string): Promise<ServiceResponse<{ path: string }>> {
        try {
            const fileName = `${title.replace(/[^a-z0-9]/gi, '_').toLowerCase()}.md`;
            const fullPath = path.join(dir, fileName);
            await fs.writeFile(fullPath, content);
            return { success: true, data: { path: fullPath } };
        } catch (e) {
            return { success: false, error: getErrorMessage(e as Error) };
        }
    }

    async unzip(zipPath: string, destPath: string): Promise<ServiceResponse> {
        try {
            this.validatePath(zipPath);
            this.validatePath(destPath);

            const { spawn } = await import('child_process');

            return new Promise((resolve) => {
                let proc;
                if (process.platform === 'win32') {
                    // Use powershell with array arguments to prevent injection
                    proc = spawn('powershell.exe', [
                        '-NoProfile',
                        '-NonInteractive',
                        '-Command',
                        'Expand-Archive',
                        '-Path',
                        zipPath,
                        '-DestinationPath',
                        destPath,
                        '-Force'
                    ]);
                } else {
                    proc = spawn('unzip', ['-o', zipPath, '-d', destPath]);
                }

                let error = '';
                proc.stderr.on('data', (data) => error += data.toString());
                proc.on('close', (code) => {
                    if (code === 0) { resolve({ success: true, message: `Extracted to ${destPath}` }); }
                    else { resolve({ success: false, error: error || `Exit code ${code}` }); }
                });
            });
        } catch (e) {
            return { success: false, error: getErrorMessage(e as Error) };
        }
    }

    async batchRename(dir: string, pattern: string, replacement: string): Promise<ServiceResponse> {
        try {
            this.validatePath(dir);
            const files = await fs.readdir(dir);
            let count = 0;
            for (const file of files) {
                if (file.includes(pattern)) {
                    const newName = file.replace(pattern, replacement);
                    await fs.rename(path.join(dir, file), path.join(dir, newName));
                    count++;
                }
            }
            return { success: true, message: `${count} files renamed.` };
        } catch (e) {
            return { success: false, error: getErrorMessage(e as Error) };
        }
    }

    watchFolder(dir: string, callback?: (event: string, filename: string) => void): ServiceResponse<{ close: () => void }> {
        try {
            this.validatePath(dir);
            const absoluteDir = path.resolve(dir);
            const watcher = watch(absoluteDir, { recursive: true }, (eventType, filename) => {
                if (!filename) { return; }
                if (this.shouldIgnore(path.join(absoluteDir, filename.toString()))) { return; }

                // Debounce or just emission could be handled by caller, but basic log here
                appLogger.info('filesystem.service', `[FileWatcher] ${eventType}: ${filename}`);
                if (callback) { callback(eventType, filename.toString()); }
            });

            return {
                success: true,
                message: `Watching ${dir} for changes...`,
                data: { close: () => watcher.close() }
            };
        } catch (e) {
            return { success: false, error: getErrorMessage(e as Error) };
        }
    }

    async downloadFile(url: string, destPath: string): Promise<ServiceResponse<{ path: string }>> {
        if (!this.isPathAllowed(destPath)) {
            return { success: false, error: 'Access denied: Path is outside allowed directories' };
        }
        return new Promise((resolve) => {
            const file = createWriteStream(destPath);
            https.get(url, (response: import('http').IncomingMessage) => {
                response.pipe(file);
                file.on('finish', () => {
                    file.close();
                    resolve({ success: true, data: { path: destPath } });
                });
            }).on('error', (err: Error) => {
                fs.unlink(destPath).catch(() => { });
                resolve({ success: false, error: err.message });
            });
        });
    }

    async getFileHash(filePath: string, algorithm: 'md5' | 'sha1' | 'sha256' = 'sha256'): Promise<ServiceResponse<string>> {
        try {
            this.validatePath(filePath);
            const { createHash } = await import('crypto');
            const content = await fs.readFile(path.resolve(filePath));
            const hash = createHash(algorithm).update(content).digest('hex');
            return { success: true, data: hash };
        } catch (error) {
            return { success: false, error: getErrorMessage(error as Error) };
        }
    }

    async searchFiles(rootPath: string, pattern: string): Promise<ServiceResponse<string[]>> {
        try {
            const results: string[] = [];
            await this.searchFilesStream(rootPath, pattern, (path) => results.push(path));
            return { success: true, data: results };
        } catch (error) {
            return { success: false, error: getErrorMessage(error as Error) };
        }
    }

    async searchFilesStream(rootPath: string, pattern: string, onResult: (path: string) => void): Promise<void> {
        this.validatePath(rootPath);
        const walk = async (dir: string) => {
            try {
                const entries = await fs.readdir(dir, { withFileTypes: true });
                for (const entry of entries) {
                    const full = path.join(dir, entry.name);
                    if (this.shouldIgnore(full)) { continue; }

                    if (entry.isDirectory()) {
                        await walk(full);
                    } else if (entry.name.includes(pattern)) {
                        onResult(full);
                    }
                }
            } catch {
                // Ignore access errors during search
            }
        };
        await walk(path.resolve(rootPath));
    }

    async applyEdits(filePath: string, edits: { startLine: number, endLine: number, replacement: string }[]): Promise<ServiceResponse> {
        try {
            const result = await this.readFile(filePath);
            if (!result.success || !result.data) { return { success: false, error: result.error ?? 'File read failed' }; }

            const lines = result.data.split('\n');
            const sortedEdits = [...edits].sort((a, b) => b.startLine - a.startLine);

            for (const edit of sortedEdits) {
                if (edit.startLine < 1 || edit.endLine > lines.length || edit.startLine > edit.endLine) {
                    return { success: false, error: `Invalid line range: ${edit.startLine}-${edit.endLine} (File has ${lines.length} lines)` };
                }

                const start = edit.startLine - 1;
                const count = edit.endLine - edit.startLine + 1;
                lines.splice(start, count, edit.replacement);
            }

            const newContent = lines.join('\n');
            const writeResult = await this.writeFile(filePath, newContent);
            if (!writeResult.success) {
                return { success: false, error: writeResult.error ?? 'Failed to write edited file content' };
            }
            return { success: true, message: `Applied ${edits.length} edits to ${filePath}` };
        } catch (e) {
            return { success: false, error: getErrorMessage(e as Error) };
        }
    }
}

