const ITEMS_PER_PAGE = 24;

export const MCPStore: React.FC<{
    onInstall?: (id: string) => void
    onUninstall?: (id: string) => void
    onConfigure?: (id: string) => void
}> = ({ onInstall, onUninstall, onConfigure }) => {
    const { t } = useTranslation();
    const [searchQuery, setSearchQuery] = useState('');
    const [selectedCategory, setSelectedCategory] = useState('all');
    const [selectedTool, setSelectedTool] = useState<McpMarketplaceServer | null>(null);
    const [marketplaceServers, setMarketplaceServers] = useState<McpMarketplaceServer[]>([]);
    const [installedServers, setInstalledServers] = useState<MCPServerConfig[]>([]);
    const [loading, setLoading] = useState(true);
    const [currentPage, setCurrentPage] = useState(1);

    // Load marketplace servers
    const loadMarketplace = useCallback(async () => {
        try {
            setLoading(true);
            const result = await window.electron.mcpMarketplace.list();
            if (result.success && result.servers) {
                // Properly cast from IpcValue[] to McpMarketplaceServer[]
                const servers = result.servers as unknown as McpMarketplaceServer[];
                setMarketplaceServers(servers);
            }
        } catch (error) {
            console.error('Failed to load marketplace:', error);
        } finally {
            setLoading(false);
        }
    }, []);

    // Load installed servers
    const loadInstalled = useCallback(async () => {
        try {
            const result = await window.electron.mcpMarketplace.installed();
            if (result.success && result.servers) {
                // Properly cast from IpcValue[] to MCPServerConfig[]
                const servers = result.servers as unknown as MCPServerConfig[];
                setInstalledServers(servers);
            }
        } catch (error) {
            console.error('Failed to load installed servers:', error);
        }
    }, []);

    useEffect(() => {
        void loadMarketplace();
        void loadInstalled();
    }, [loadMarketplace, loadInstalled]);

    const handleInstall = useCallback(
        async (serverId: string) => {
            try {
                const result = await window.electron.mcpMarketplace.install(serverId);
                if (result.success) {
                    await loadInstalled();
                    onInstall?.(serverId);
                }
            } catch (error) {
                console.error('Failed to install server:', error);
            }
        },
        [loadInstalled, onInstall]
    );

    const handleUninstall = useCallback(
        async (serverId: string) => {
            try {
                const result = await window.electron.mcpMarketplace.uninstall(serverId);
                if (result.success) {
                    await loadInstalled();
                    onUninstall?.(serverId);
                }
            } catch (error) {
                console.error('Failed to uninstall server:', error);
            }
        },
        [loadInstalled, onUninstall]
    );

    const installedIds = useMemo(() => new Set(installedServers.map((s) => s.id)), [installedServers]);

    const filteredTools = useMemo(() => {
        let filtered = marketplaceServers;

        // Filter by category
        if (selectedCategory !== 'all') {
            filtered = filtered.filter((server) => server.categories?.includes(selectedCategory));
        }

        // Filter by search query
        if (searchQuery) {
            const q = searchQuery.toLowerCase();
            filtered = filtered.filter(
                (server) =>
                    server.name?.toLowerCase().includes(q) ||
                    server.description?.toLowerCase().includes(q) ||
                    server.publisher?.toLowerCase().includes(q) ||
                    server.categories?.some((cat) => cat.toLowerCase().includes(q))
            );
        }

        return filtered;
    }, [marketplaceServers, selectedCategory, searchQuery]);

    // Paginated tools
    const paginatedTools = useMemo(() => {
        const startIndex = (currentPage - 1) * ITEMS_PER_PAGE;
        const endIndex = startIndex + ITEMS_PER_PAGE;
        return filteredTools.slice(startIndex, endIndex);
    }, [filteredTools, currentPage]);

    const totalPages = Math.ceil(filteredTools.length / ITEMS_PER_PAGE);

    // Reset to page 1 when filters change
    useEffect(() => {
        setCurrentPage(1);
    }, [searchQuery, selectedCategory]);

    const installedCount = installedServers.length;

    return (
        <div className="h-full flex flex-col">
            <div className="p-4 border-b border-border/30">
                <div className="flex items-center gap-3 mb-4">
                    <div className="p-2 rounded-lg bg-primary/10">
                        <Plug className="w-6 h-6 text-primary" />
                    </div>
                    <div>
                        <h1 className="text-lg font-bold">{t('mcp.storeTitle')}</h1>
                        <p className="text-xs text-muted-foreground">
                            {t('mcp.storeSubtitle', { count: installedCount })}
                        </p>
                    </div>
                </div>
                <div className="relative mb-3">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground/50" />
                    <input
                        type="text"
                        placeholder={t('mcp.searchTools')}
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                        className="w-full bg-muted/30 border border-border/30 rounded-lg pl-9 pr-3 py-2 text-sm outline-none"
                    />
                </div>
                <div className="flex gap-2 overflow-x-auto pb-1">
                    {CATEGORIES.map(({ id, labelKey, icon: Icon }) => (
                        <button
                            key={id}
                            onClick={() => setSelectedCategory(id)}
                            className={cn(
                                'flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-xs font-medium whitespace-nowrap transition-colors',
                                selectedCategory === id
                                    ? 'bg-primary text-primary-foreground'
                                    : 'bg-muted/30 text-muted-foreground hover:bg-muted/50'
                            )}
                        >
                            <Icon className="w-3.5 h-3.5" />
                            {t(labelKey)}
                        </button>
                    ))}
                </div>
            </div>
            <div className="flex-1 overflow-y-auto p-4">
                {loading ? (
                    <div className="flex items-center justify-center py-12">
                        <p className="text-sm text-muted-foreground">{t('common.loading')}</p>
                    </div>
                ) : (
                    <>
                        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                            {paginatedTools.map((tool) => (
                                <ToolCard
                                    key={tool.id}
                                    tool={tool}
                                    isInstalled={installedIds.has(tool.id)}
                                    onSelect={setSelectedTool}
                                    onInstall={handleInstall}
                                    onUninstall={handleUninstall}
                                    onConfigure={onConfigure}
                                    t={t}
                                />
                            ))}
                        </div>
                        {filteredTools.length === 0 && (
                            <div className="flex flex-col items-center justify-center py-12 text-muted-foreground/50">
                                <Plug className="w-12 h-12 mb-3 opacity-30" />
                                <p className="text-sm">{t('mcp.noToolsFound')}</p>
                            </div>
                        )}
                        {totalPages > 1 && (
                            <div className="flex items-center justify-center gap-2 mt-6 pb-4">
                                <button
                                    onClick={() => setCurrentPage(p => Math.max(1, p - 1))}
                                    disabled={currentPage === 1}
                                    className={cn(
                                        'px-3 py-1.5 rounded-md text-sm font-medium transition-colors',
                                        currentPage === 1
                                            ? 'bg-muted/30 text-muted-foreground/50 cursor-not-allowed'
                                            : 'bg-muted/50 text-foreground hover:bg-muted'
                                    )}
                                >
                                    {t('common.previous')}
                                </button>
                                <span className="text-sm text-muted-foreground px-3">
                                    {t('common.pageOf', { current: currentPage, total: totalPages })}
                                </span>
                                <button
                                    onClick={() => setCurrentPage(p => Math.min(totalPages, p + 1))}
                                    disabled={currentPage === totalPages}
                                    className={cn(
                                        'px-3 py-1.5 rounded-md text-sm font-medium transition-colors',
                                        currentPage === totalPages
                                            ? 'bg-muted/30 text-muted-foreground/50 cursor-not-allowed'
                                            : 'bg-muted/50 text-foreground hover:bg-muted'
                                    )}
                                >
                                    {t('common.next')}
                                </button>
                            </div>
                        )}
                    </>
                )}
            </div>
            {selectedTool && (
                <ToolDetailModal
                    tool={selectedTool}
                    isInstalled={installedIds.has(selectedTool.id)}
                    onInstall={handleInstall}
                    onUninstall={handleUninstall}
                    onConfigure={onConfigure}
                    onClose={() => setSelectedTool(null)}
                    t={t}
                />
            )}
        </div>
    );
};

