    selectedModels?: Array<{ provider: string; model: string }>;
    onSelect: (provider: string, model: string, isMultiSelect?: boolean) => void;
    settings?: AppSettings;
    groupedModels?: GroupedModels;
    quotas?: { accounts: QuotaResponse[] } | null;
    codexUsage?: { accounts: { usage: CodexUsage }[] } | null;
    claudeQuota?: { accounts: ClaudeQuota[] } | null;
    onOpenChange?: (isOpen: boolean) => void;
    contextTokens?: number;
    language?: Language;
    onRemoveModel?: (provider: string, model: string) => void;
    isFavorite?: (modelId: string) => boolean;
    toggleFavorite?: (modelId: string) => void;
    isIconOnly?: boolean;
    thinkingLevel?: string;
    onThinkingLevelChange?: (level: string) => void;
}

export function ModelSelector({
    selectedProvider,
    selectedModel,
    selectedModels = [],
    onSelect,
    settings,
    groupedModels,
    quotas = null,
    codexUsage = null,
    claudeQuota = null,
    onOpenChange,
    contextTokens = 0,
    language = 'en',
    onRemoveModel,
    isFavorite,
    toggleFavorite,
    isIconOnly,
    thinkingLevel,
    onThinkingLevelChange
}: ModelSelectorProps) {
    const { t } = useTranslation(language);
    const [isOpen, setIsOpen] = useState(false);
    const [searchQuery] = useState('');
    const debouncedSearchQuery = useDebounce(searchQuery, 300);

    useEffect(() => { onOpenChange?.(isOpen); }, [isOpen, onOpenChange]);

    const { isModelDisabled } = useModelSelectorLogic({ settings, groupedModels, quotas, codexUsage, claudeQuota });
    const categories = useModelCategories({ groupedModels, debouncedSearchQuery, settings, selectedModel, isModelDisabled, t });

    const normalizeProvider = useCallback((provider?: string) => {
        const p = (provider ?? '').toLowerCase();
        if (p === 'codex') { return 'openai'; }
        if (p === 'github') { return 'copilot'; }
        if (p === 'anthropic') { return 'claude'; }
        return p;
    }, []);

    const normalizedSelectedProvider = useMemo(() => {
        return normalizeProvider(selectedProvider);
    }, [selectedProvider, normalizeProvider]);

    const currentModelInfo = useMemo(() => {
        const normalized = selectedModel.toLowerCase();
        if (normalizedSelectedProvider) {
            for (const cat of categories) {
                const m = cat.models.find(m =>
                    (m.id === selectedModel || m.id.toLowerCase() === normalized) &&
                    normalizeProvider(m.provider) === normalizedSelectedProvider
                );
                if (m) { return m; }
            }
        }
        for (const cat of categories) {
            const m = cat.models.find(m => m.id === selectedModel || m.id.toLowerCase() === normalized);
            if (m) { return m; }
        }
        return null;
    }, [categories, selectedModel, normalizedSelectedProvider, normalizeProvider]);

    const contextLimit = useMemo(() => {
        if (currentModelInfo?.contextWindow) { return currentModelInfo.contextWindow; }
        const id = selectedModel.toLowerCase();
        if (id.includes('gpt-4') || id.includes('o1') || id.includes('gpt-5')) { return 128000; }
        if (id.includes('claude-3')) { return 200000; }
        if (id.includes('gemini-1.5')) { return 1000000; }
        return 32000;
    }, [selectedModel, currentModelInfo]);

    const contextUsagePercent = Math.min(100, (contextTokens / contextLimit) * 100);

    const effectiveThinkingLevel = useMemo(() => {
        const levels = currentModelInfo?.thinkingLevels;
        if (!levels || levels.length === 0) { return undefined; }
        if (thinkingLevel && levels.includes(thinkingLevel)) { return thinkingLevel; }
        if (levels.includes('medium')) { return 'medium'; }
        return levels[0];
    }, [currentModelInfo, thinkingLevel]);

    const handleModelSelect = useCallback((p: string, id: string, m?: boolean, keepOpen?: boolean) => {
        onSelect(p, id, m);
        if (!m && !keepOpen) { setIsOpen(false); }
    }, [onSelect]);

    const handleClose = useCallback(() => {
        setIsOpen(false);
    }, []);

    const currentCat = categories.find(c => c.models.some(m =>
        m.id === selectedModel &&
        (!normalizedSelectedProvider || normalizeProvider(m.provider) === normalizedSelectedProvider)
    )) ?? categories.find(c => c.models.some(m => m.id === selectedModel)) ?? categories.find(c => c.id === normalizedSelectedProvider);

    // Get recent models from settings
    const recentModels = settings?.general?.recentModels ?? [];

    return (
        <div className="relative">
            <ModelSelectorTrigger
                isOpen={isOpen}
                setIsOpen={setIsOpen}
                currentCategory={currentCat}
                currentModelInfo={currentModelInfo}
                selectedModel={selectedModel}
                selectedModels={selectedModels}
                contextTokens={contextTokens}
                contextUsagePercent={contextUsagePercent}
                t={t}
                isIconOnly={isIconOnly}
            />

            <ModelSelectorModal
                isOpen={isOpen}
                onClose={handleClose}
                categories={categories}
                selectedModels={selectedModels}
                selectedModel={selectedModel}
                selectedProvider={selectedProvider}
                onSelect={handleModelSelect}
                onRemoveModel={onRemoveModel}
                isFavorite={isFavorite}
                toggleFavorite={toggleFavorite}
                recentModels={recentModels}
                t={t}
                thinkingLevel={effectiveThinkingLevel}
                onThinkingLevelChange={onThinkingLevelChange}
            />
        </div>
    );
}

import { Bot, Brain, Clock, Search, Sparkles, Star, X, Zap } from 'lucide-react';
import React, { useCallback, useEffect, useMemo, useRef, useState } from 'react';
import { createPortal } from 'react-dom';

import { cn } from '@/lib/utils';

import { ModelCategory, ModelListItem } from '../types';

import { ModelSelectorItem } from './ModelSelectorItem';

export type ChatMode = 'instant' | 'thinking' | 'agent';
export type ThinkingLevel = 'none' | 'minimal' | 'low' | 'medium' | 'high' | 'xhigh' | 'max' | string;
interface ModelSelectorModalProps {
    isOpen: boolean;
    onClose: () => void;
    categories: ModelCategory[];
    selectedModels: Array<{ provider: string; model: string }>;
    selectedModel: string;
    selectedProvider: string;
    onSelect: (provider: string, id: string, isMultiSelect: boolean, keepOpen?: boolean) => void;
    onRemoveModel?: (provider: string, model: string) => void;
    isFavorite?: (modelId: string) => boolean;
    toggleFavorite?: (modelId: string) => void;
    recentModels?: string[];
    t: (key: string) => string;
    chatMode?: ChatMode;
    onChatModeChange?: (mode: ChatMode) => void;
    thinkingLevel?: string;
    onThinkingLevelChange?: (level: string) => void;
    onConfirmSelection?: () => void;
}

const MODE_CONFIG: Record<ChatMode, { icon: React.ElementType; color: string; bg: string }> = {
    instant: { icon: Zap, color: 'text-yellow-500', bg: 'bg-yellow-500/10' },
    thinking: { icon: Brain, color: 'text-purple-500', bg: 'bg-purple-500/10' },
    agent: { icon: Bot, color: 'text-blue-500', bg: 'bg-blue-500/10' }
};

const THINKING_LEVEL_LABELS: Record<ThinkingLevel, string> = {
    none: 'None',
    minimal: 'Minimal',
    low: 'Low',
    medium: 'Medium',
    high: 'High',
    xhigh: 'Max'
};

export const ModelSelectorModal: React.FC<ModelSelectorModalProps> = ({
    isOpen,
    onClose,
    categories,
    selectedModels,
    selectedModel,
    selectedProvider,
    onSelect,
    toggleFavorite,
    recentModels = [],
    t,
    chatMode = 'instant',
    onChatModeChange,
    thinkingLevel = 'medium',
    onThinkingLevelChange,
    onConfirmSelection
}) => {
    const modalRef = useRef<HTMLDivElement>(null);
    const searchInputRef = useRef<HTMLInputElement>(null);
    const [searchQuery, setSearchQuery] = useState('');
    const [activeTab, setActiveTab] = useState<'models' | 'reasoning'>('models');
    const [pendingModel, setPendingModel] = useState<{ provider: string; id: string } | null>(null);
    const [pendingThinkingLevel, setPendingThinkingLevel] = useState<string | null>(null);

    // Check if pending model requires reasoning level selection
    const pendingModelThinkingLevels = useMemo(() => {
        if (!pendingModel) { return null; }
        for (const cat of categories) {
            const found = cat.models.find(m => m.id === pendingModel.id && m.provider === pendingModel.provider);
            if (found?.thinkingLevels && found.thinkingLevels.length > 0) { return found.thinkingLevels; }
        }
        return null;
    }, [categories, pendingModel]);

    const requiresReasoningSelection = pendingModel !== null && pendingModelThinkingLevels !== null && pendingModelThinkingLevels.length > 0;
    const canConfirm = !requiresReasoningSelection || pendingThinkingLevel !== null;

    const handleClose = useCallback(() => {
        if (searchQuery) { setSearchQuery(''); }
        setActiveTab('models');
        setPendingModel(null);
        setPendingThinkingLevel(null);
        onClose();
    }, [onClose, searchQuery]);

    const handleCancelPending = useCallback(() => {
        setPendingModel(null);
        setPendingThinkingLevel(null);
        setActiveTab('models');
    }, []);

    // ESC key handler
    useEffect(() => {
        if (!isOpen) { return; }
        const handleEscape = (e: KeyboardEvent) => {
            if (e.key === 'Escape') {
                if (requiresReasoningSelection && !canConfirm) {
                    handleCancelPending();
                    return;
                }
                handleClose();
            }
        };
        document.addEventListener('keydown', handleEscape);
        return () => document.removeEventListener('keydown', handleEscape);
    }, [handleClose, handleCancelPending, isOpen, requiresReasoningSelection, canConfirm]);

    // Body scroll lock
    useEffect(() => {
        document.body.style.overflow = isOpen ? 'hidden' : '';
        return () => { document.body.style.overflow = ''; };
    }, [isOpen]);

    // Auto focus search input
    useEffect(() => {
        if (isOpen && searchInputRef.current) {
            setTimeout(() => searchInputRef.current?.focus(), 100);
        }
    }, [isOpen]);

    // Get favorite models from categories
    const favoriteModels = useMemo(() => {
        const favCat = categories.find(c => c.id === 'favorites');
        return favCat?.models ?? [];
    }, [categories]);

    // Get recent models from all categories
    const recentModelItems = useMemo(() => {
        if (recentModels.length === 0) { return []; }
        const items: ModelListItem[] = [];
        for (const recentId of recentModels.slice(0, 5)) {
            for (const cat of categories) {
                const found = cat.models.find(m => m.id === recentId);
                if (found && !items.some(i => i.id === found.id)) {
                    items.push(found);
                    break;
                }
            }
        }
        return items;
    }, [categories, recentModels]);

    // Get current model's thinking levels
    const currentModelThinkingLevels = useMemo(() => {
        for (const cat of categories) {
            const found = cat.models.find(m => m.id === selectedModel);
            if (found?.thinkingLevels) { return found.thinkingLevels; }
        }
        return null;
    }, [categories, selectedModel]);

    const currentModelInfo = useMemo(() => {
        for (const cat of categories) {
            const found = cat.models.find(m => m.id === selectedModel);
            if (found) { return found; }
        }
        return null;
    }, [categories, selectedModel]);

    useEffect(() => {
        let timer: NodeJS.Timeout | undefined;
        if (activeTab === 'reasoning' && (!currentModelThinkingLevels || currentModelThinkingLevels.length === 0)) {
            // Use setTimeout to avoid synchronous setState in effect body
            timer = setTimeout(() => setActiveTab('models'), 0);
        }
        return () => {
            if (timer) { clearTimeout(timer); }
        };
    }, [activeTab, currentModelThinkingLevels]);

    const supportsReasoning = useCallback((provider: string, id: string) => {
        for (const cat of categories) {
            const found = cat.models.find(m => m.id === id && m.provider === provider);
            if (found?.thinkingLevels && found.thinkingLevels.length > 0) { return true; }
        }
        return false;
    }, [categories]);

    // Filter categories based on search
    const filteredCategories = useMemo(() => {
        if (!searchQuery.trim()) {
            return categories.filter(c => c.id !== 'favorites');
        }
        const query = searchQuery.toLowerCase();
        return categories
            .filter(c => c.id !== 'favorites')
            .map(cat => ({
                ...cat,
                models: cat.models.filter(m =>
                    m.label.toLowerCase().includes(query) ||
                    m.id.toLowerCase().includes(query)
                )
            }))
            .filter(cat => cat.models.length > 0);
    }, [categories, searchQuery]);

    const handleSelect = useCallback((provider: string, id: string, isMulti: boolean) => {
        if (isMulti) {
            onSelect(provider, id, isMulti, true);
            return;
        }

        const hasReasoning = supportsReasoning(provider, id);
        if (hasReasoning) {
            setPendingModel({ provider, id });
            setPendingThinkingLevel(null);
            setActiveTab('reasoning');
            return;
        }

        onSelect(provider, id, isMulti, false);
        handleClose();
    }, [handleClose, onSelect, supportsReasoning]);

    const handlePendingThinkingLevelChange = useCallback((level: string) => {
        setPendingThinkingLevel(level);
        onThinkingLevelChange?.(level);
    }, [onThinkingLevelChange]);

    const handleConfirmSelection = useCallback(() => {
        if (!pendingModel || !canConfirm) { return; }
        onSelect(pendingModel.provider, pendingModel.id, false, false);
        onConfirmSelection?.();
        handleClose();
    }, [pendingModel, canConfirm, onSelect, onConfirmSelection, handleClose]);

    const handleBackdropClick = useCallback((e: React.MouseEvent) => {
        if (e.target === e.currentTarget) {
            if (requiresReasoningSelection && !canConfirm) { return; }
            handleClose();
        }
    }, [handleClose, requiresReasoningSelection, canConfirm]);

    if (!isOpen) { return null; }

    return createPortal(
        <div
            className="fixed inset-0 z-50 flex items-center justify-center p-4"
            role="dialog"
            aria-modal="true"
            aria-labelledby="model-selector-title"
            onClick={handleBackdropClick}
        >
            {/* Backdrop */}
            <div
                className="absolute inset-0 bg-black/60 backdrop-blur-sm animate-in fade-in-0 duration-200"
                aria-hidden="true"
            />

            {/* Modal */}
            <div
                ref={modalRef}
                className={cn(
                    'relative w-full max-w-3xl max-h-[85vh] flex flex-col',
                    'bg-popover/95 backdrop-blur-xl rounded-2xl shadow-2xl',
                    'border border-border/50',
                    'animate-in fade-in-0 zoom-in-95 duration-200'
                )}
                onClick={e => e.stopPropagation()}
            >
                {/* Header */}
                <div className="flex items-center justify-between p-4 border-b border-border/50">
                    <div className="flex items-center gap-2">
                        <Sparkles className="w-5 h-5 text-primary" />
                        <h2 id="model-selector-title" className="text-lg font-semibold">
                            {t('modelSelector.selectModel')}
                        </h2>
                    </div>
                    <button
                        onClick={handleClose}
                        className="p-2 rounded-lg hover:bg-muted/50 transition-colors"
                        aria-label={t('common.close')}
                    >
                        <X className="w-5 h-5" />
                    </button>
                </div>

                {/* Mode & Tabs */}
                <div className="px-4 py-3 border-b border-border/50 flex flex-wrap items-center gap-4">
                    <div className="flex items-center gap-2">
                        <span className="text-xs text-muted-foreground font-medium">{t('modelSelector.mode')}:</span>
                        <div className="flex gap-1 bg-muted/30 rounded-lg p-1">
                            {(Object.keys(MODE_CONFIG) as ChatMode[]).map(mode => {
                                const config = MODE_CONFIG[mode];
                                const Icon = config.icon;
                                const isActive = chatMode === mode;
                                return (
                                    <button
                                        key={mode}
                                        onClick={() => onChatModeChange?.(mode)}
                                        className={cn(
                                            'flex items-center gap-1.5 px-3 py-1.5 rounded-md text-xs font-medium transition-all',
                                            isActive ? cn(config.bg, config.color) : 'text-muted-foreground hover:text-foreground hover:bg-muted/50'
                                        )}
                                    >
                                        <Icon className="w-3.5 h-3.5" />
                                        <span className="capitalize">{mode}</span>
                                    </button>
                                );
                            })}
                        </div>
                    </div>

                    {currentModelThinkingLevels && currentModelThinkingLevels.length > 0 && (
                        <div className="flex items-center gap-1 bg-muted/30 rounded-lg p-1 ml-auto">
                            <button
                                onClick={() => setActiveTab('models')}
                                className={cn(
                                    'px-3 py-1.5 rounded-md text-xs font-medium transition-all',
                                    activeTab === 'models' ? 'bg-primary/20 text-primary' : 'text-muted-foreground hover:text-foreground hover:bg-muted/50'
                                )}
                            >
                                Models
                            </button>
                            <button
                                onClick={() => setActiveTab('reasoning')}
                                className={cn(
                                    'px-3 py-1.5 rounded-md text-xs font-medium transition-all',
                                    activeTab === 'reasoning' ? 'bg-primary/20 text-primary' : 'text-muted-foreground hover:text-foreground hover:bg-muted/50'
                                )}
                            >
                                Reasoning
                            </button>
                        </div>
                    )}
                </div>

                {/* Search */}
                {activeTab === 'models' && (
                    <div className="p-3 border-b border-border/50">
                        <div className="flex items-center gap-2 bg-muted/30 rounded-lg px-3 py-2 border border-border/50 focus-within:border-primary/50 transition-colors">
                            <Search className="w-4 h-4 text-muted-foreground" />
                            <input
                                ref={searchInputRef}
                                type="text"
                                placeholder={t('modelSelector.searchModels')}
                                value={searchQuery}
                                onChange={(e) => setSearchQuery(e.target.value)}
                                className="bg-transparent border-none p-0 text-sm focus:ring-0 w-full placeholder:text-muted-foreground/50 outline-none text-foreground"
                            />
                        </div>
                    </div>
                )}

                {/* Content - Scrollable */}
                <div className="flex-1 overflow-y-auto custom-scrollbar">
                    {/* Pending Model Reasoning Selection */}
                    {activeTab === 'reasoning' && pendingModel && pendingModelThinkingLevels && pendingModelThinkingLevels.length > 0 && (
                        <div className="p-4">
                            <div className="mb-4 p-3 bg-primary/5 border border-primary/20 rounded-lg">
                                <div className="flex items-center gap-2 mb-1">
                                    <Brain className="w-4 h-4 text-primary" />
                                    <span className="text-sm font-medium text-foreground">
                                        {t('modelSelector.selectReasoningLevel')}
                                    </span>
                                </div>
                                <p className="text-xs text-muted-foreground">
                                    {t('modelSelector.reasoningRequired')}
                                </p>
                            </div>
                            <div className="text-xs text-muted-foreground font-medium mb-3">
                                {categories.flatMap(c => c.models).find(m => m.id === pendingModel.id)?.label ?? pendingModel.id}
                            </div>
                            <div className="flex flex-wrap gap-2 mb-4">
                                {pendingModelThinkingLevels.map(level => {
                                    const isActive = pendingThinkingLevel === level;
                                    return (
                                        <button
                                            key={level}
                                            onClick={() => handlePendingThinkingLevelChange(level)}
                                            className={cn(
                                                'px-4 py-2 rounded-lg text-sm font-medium transition-all border',
                                                isActive
                                                    ? 'bg-primary text-primary-foreground border-primary shadow-md'
                                                    : 'border-border/50 text-muted-foreground hover:text-foreground hover:bg-muted/50 hover:border-border'
                                            )}
                                        >
                                            {THINKING_LEVEL_LABELS[level as ThinkingLevel] ?? level}
                                        </button>
                                    );
                                })}
                            </div>
                            <div className="flex items-center gap-2 pt-3 border-t border-border/50">
                                <button
                                    onClick={handleCancelPending}
                                    className="px-4 py-2 text-sm font-medium text-muted-foreground hover:text-foreground hover:bg-muted/50 rounded-lg transition-colors"
                                >
                                    {t('common.cancel')}
                                </button>
                                <button
                                    onClick={handleConfirmSelection}
                                    disabled={!canConfirm}
                                    className={cn(
                                        'flex-1 px-4 py-2 rounded-lg text-sm font-medium transition-all',
                                        canConfirm
                                            ? 'bg-primary text-primary-foreground hover:bg-primary/90'
                                            : 'bg-muted text-muted-foreground cursor-not-allowed'
                                    )}
                                >
                                    {canConfirm ? t('modelSelector.confirmModel') : t('modelSelector.selectLevelFirst')}
                                </button>
                            </div>
                        </div>
                    )}

                    {/* Current Model Reasoning (when not in pending state) */}
                    {activeTab === 'reasoning' && !pendingModel && currentModelThinkingLevels && currentModelThinkingLevels.length > 0 && (
                        <div className="p-4">
                            <div className="text-xs text-muted-foreground font-medium mb-2">
                                {t('modelSelector.reasoning')} • {currentModelInfo?.label ?? selectedModel}
                            </div>
                            <div className="flex flex-wrap gap-2">
                                {currentModelThinkingLevels.map(level => {
                                    const isActive = thinkingLevel === level;
                                    return (
                                        <button
                                            key={level}
                                            onClick={() => onThinkingLevelChange?.(level)}
                                            className={cn(
                                                'px-3 py-1.5 rounded-md text-xs font-medium transition-all border border-border/50',
                                                isActive ? 'bg-primary/20 text-primary' : 'text-muted-foreground hover:text-foreground hover:bg-muted/50'
                                            )}
                                        >
                                            {THINKING_LEVEL_LABELS[level as ThinkingLevel] ?? level}
                                        </button>
                                    );
                                })}
                            </div>
                        </div>
                    )}

                    {/* Favorites Section */}
                    {activeTab === 'models' && !searchQuery && favoriteModels.length > 0 && (
                        <ModelSection
                            title={t('common.favorites')}
                            icon={<Star className="w-3.5 h-3.5 text-yellow-500" />}
                            models={favoriteModels}
                            selectedModels={selectedModels}
                            selectedModel={selectedModel}
                            selectedProvider={selectedProvider}
                            onSelect={handleSelect}
                            toggleFavorite={toggleFavorite}
                            t={t}
                        />
                    )}

                    {/* Recent Models Section */}
                    {activeTab === 'models' && !searchQuery && recentModelItems.length > 0 && (
                        <ModelSection
                            title={t('modelSelector.recentModels')}
                            icon={<Clock className="w-3.5 h-3.5 text-muted-foreground" />}
                            models={recentModelItems}
                            selectedModels={selectedModels}
                            selectedModel={selectedModel}
                            selectedProvider={selectedProvider}
                            onSelect={handleSelect}
                            toggleFavorite={toggleFavorite}
                            t={t}
                        />
                    )}

                    {/* All Models by Category */}
                    {activeTab === 'models' && filteredCategories.length === 0 ? (
                        <div className="p-8 text-center text-muted-foreground">
                            <Search className="w-8 h-8 mx-auto mb-2 opacity-50" />
                            <p>{t('modelSelector.noModelsFound')}</p>
                        </div>
                    ) : activeTab === 'models' ? (
                        filteredCategories.map(category => (
                            <div key={category.id} className="border-b border-border/30 last:border-b-0">
                                <div className="px-4 py-2 text-xs font-semibold uppercase tracking-wider text-muted-foreground flex items-center gap-2 bg-muted/20">
                                    <category.icon className={cn('w-3.5 h-3.5', category.color)} />
                                    <span>{category.name}</span>
                                    <span className="text-muted-foreground/50 font-normal">({category.models.length})</span>
                                </div>
                                <div className="p-2 grid grid-cols-1 sm:grid-cols-2 gap-1">
                                    {category.models.map(model => (
                                        <ModelSelectorItem
                                            key={`${category.id}-${model.provider}-${model.id}`}
                                            model={model}
                                            isSelected={selectedModels.some(m => m.provider === model.provider && m.model === model.id)}
                                            isPrimary={selectedModel === model.id && selectedProvider === model.provider}
                                            onSelect={handleSelect}
                                            toggleFavorite={toggleFavorite}
                                            t={t}
                                            modelIndex={selectedModels.findIndex(m => m.provider === model.provider && m.model === model.id)}
                                        />
                                    ))}
                                </div>
                            </div>
                        ))
                    ) : null}
                </div>

                {/* Footer */}
                <div className="px-4 py-3 border-t border-border/50 bg-muted/20 text-xs text-muted-foreground flex items-center justify-between">
                    {requiresReasoningSelection && !canConfirm ? (
                        <span className="text-yellow-500">{t('modelSelector.mustSelectReasoning')}</span>
                    ) : (
                        <span>{t('modelSelector.shiftClickMulti')}</span>
                    )}
                    <span className="text-muted-foreground/50">
                        ESC {requiresReasoningSelection ? t('common.cancel') : t('common.toClose')}
                    </span>
                </div>
            </div>
        </div>,
        document.body
    );
};

ModelSelectorModal.displayName = 'ModelSelectorModal';

// Helper component for model sections
interface ModelSectionProps {
    title: string;
    icon: React.ReactNode;
    models: ModelListItem[];
    selectedModels: Array<{ provider: string; model: string }>;
    selectedModel: string;
    selectedProvider: string;
    onSelect: (provider: string, id: string, isMultiSelect: boolean) => void;
    toggleFavorite?: (modelId: string) => void;
    t: (key: string) => string;
}

const ModelSection: React.FC<ModelSectionProps> = ({
    title,
    icon,
    models,
    selectedModels,
    selectedModel,
    selectedProvider,
    onSelect,
    toggleFavorite,
    t
}) => (
    <div className="border-b border-border/30">
        <div className="px-4 py-2 text-xs font-semibold uppercase tracking-wider text-muted-foreground flex items-center gap-2 bg-muted/20">
            {icon}
            <span>{title}</span>
        </div>
        <div className="p-2 grid grid-cols-1 sm:grid-cols-2 gap-1">
            {models.map(model => (
                <ModelSelectorItem
                    key={`section-${model.provider}-${model.id}`}
                    model={model}
                    isSelected={selectedModels.some(m => m.provider === model.provider && m.model === model.id)}
                    isPrimary={selectedModel === model.id && selectedProvider === model.provider}
                    onSelect={onSelect}
                    toggleFavorite={toggleFavorite}
                    t={t}
                    modelIndex={selectedModels.findIndex(m => m.provider === model.provider && m.model === model.id)}
                />
            ))}
        </div>
    </div>
);

import { fetchModels, GroupedModels, groupModels, ModelInfo } from '@renderer/features/models/utils/model-fetcher';
import { useCallback, useEffect, useMemo, useState } from 'react';

import { AppSettings } from '@/types';
import { appLogger } from '@/utils/renderer-logger';

import { useModelSelection } from './useModelSelection';

export function useModelManager(
    appSettings: AppSettings | null,
    setAppSettings: (settings: AppSettings) => void
) {
    const [models, setModels] = useState<ModelInfo[]>([]);
    const [groupedModels, setGroupedModels] = useState<GroupedModels | null>(null);
    const [proxyModels, setProxyModels] = useState<ModelInfo[]>([]);
    const [isLoading, setIsLoading] = useState(false);

    const selection = useModelSelection(appSettings, setAppSettings);

    const refreshModels = useCallback(async (bypassCache = false) => {
        setIsLoading(true);
        try {
            const fetched = await fetchModels(bypassCache);
            setModels(fetched);
            setProxyModels(fetched.filter(m => m.provider !== 'ollama' && m.provider !== 'local-ai'));
            setGroupedModels(groupModels(fetched));
        } catch (error) {
            appLogger.error('ModelManager', 'Failed to refresh models', error as Error);
        } finally {
            setIsLoading(false);
        }
    }, []);

    useEffect(() => {
        void refreshModels();
    }, [refreshModels]);

    useEffect(() => {
        const hasNvidia = !!appSettings?.nvidia?.apiKey;
        const hasOpenAI = !!appSettings?.openai?.apiKey;
        const hasAnthropic = !!appSettings?.anthropic?.apiKey;
        const hasGroq = !!appSettings?.groq?.apiKey;

        if (hasNvidia || hasOpenAI || hasAnthropic || hasGroq) {
            void refreshModels(true);
        }
    }, [
        refreshModels,
        appSettings?.nvidia?.apiKey,
        appSettings?.openai?.apiKey,
        appSettings?.anthropic?.apiKey,
        appSettings?.groq?.apiKey
    ]);

    useEffect(() => {
        if (appSettings?.general.defaultModel) {
            selection.setSelectedModel(appSettings.general.defaultModel);
            selection.setSelectedProvider(appSettings.general.lastProvider ?? '');

            if (selection.selectedModels.length === 0) {
                selection.setSelectedModels([{
                    provider: appSettings.general.lastProvider ?? '',
                    model: appSettings.general.defaultModel
                }]);
            }
        }
    }, [appSettings, selection.selectedModels.length, selection]);

    const persistLastSelection = useCallback((provider: string, model: string) => {
        if (!appSettings) { return; }
        setAppSettings({
            ...appSettings,
            general: {
                ...appSettings.general,
                defaultModel: model,
                lastProvider: provider
            }
        });
    }, [appSettings, setAppSettings]);

    const toggleFavorite = useCallback((modelId: string) => {
        if (!appSettings) { return; }
        const currentFavorites = appSettings.general.favoriteModels ?? [];
        const isFav = currentFavorites.includes(modelId);
        const newFavorites = isFav
            ? currentFavorites.filter(id => id !== modelId)
            : [...currentFavorites, modelId];

        setAppSettings({
            ...appSettings,
            general: { ...appSettings.general, favoriteModels: newFavorites }
        });
    }, [appSettings, setAppSettings]);

    const isFavorite = useCallback((modelId: string) => {
        return appSettings?.general.favoriteModels?.includes(modelId) ?? false;
    }, [appSettings]);

    const getModelReasoningLevel = useCallback((modelId: string) => {
        return appSettings?.modelSettings?.[modelId]?.reasoningLevel;
    }, [appSettings]);

    const setModelReasoningLevel = useCallback((modelId: string, reasoningLevel: string) => {
        if (!appSettings) { return; }
        const modelSettings = { ...(appSettings.modelSettings ?? {}) };
        const current = modelSettings[modelId] ?? {};
        modelSettings[modelId] = { ...current, reasoningLevel };

        setAppSettings({
            ...appSettings,
            modelSettings
        });
    }, [appSettings, setAppSettings]);

    return useMemo(() => ({
        models,
        groupedModels,
        ...selection,
        proxyModels,
        isLoading,
        refreshModels,
        loadModels: refreshModels,
        persistLastSelection,
        toggleFavorite,
        isFavorite,
        getModelReasoningLevel,
        setModelReasoningLevel
    }), [
        models, groupedModels, selection, proxyModels, isLoading, refreshModels,
        persistLastSelection, toggleFavorite, isFavorite, getModelReasoningLevel, setModelReasoningLevel
    ]);
}

import { useCallback, useEffect, useState } from 'react';

import { AppSettings, ClaudeQuota, CodexUsage, QuotaResponse } from '@/types';

import type { GroupedModels } from '../utils/model-fetcher';

interface UseModelSelectorLogicProps {
    settings?: AppSettings;
    groupedModels?: GroupedModels;
    quotas?: { accounts: QuotaResponse[] } | null;
    codexUsage?: { accounts: { usage: CodexUsage }[] } | null;
    claudeQuota?: { accounts: ClaudeQuota[] } | null;
}

const ANTIGRAVITY_QUOTA_GROUPS = {
    'claude': [
        'gemini-claude-sonnet-4-5',
        'gemini-claude-sonnet-4-5-thinking',
        'gemini-claude-opus-4-5-thinking'
    ],
    'gemini-3-pro': [
        'gemini-3-pro-preview',
        'gemini-3-pro-low',
        'gemini-3-pro-high'
    ]
};

function isCodexModel(lowerModelId: string) {
    return lowerModelId.includes('codex') || lowerModelId.includes('gpt-5') || lowerModelId.includes('o1');
}

function checkCodexWeeklyLimit(usage: { weeklyLimit?: number; weeklyUsedPercent?: number }, codexLimits: { weekly?: { enabled?: boolean; percentage: number } } | undefined, lowerModelId: string) {
    if (!codexLimits?.weekly?.enabled || usage.weeklyLimit === undefined || usage.weeklyLimit <= 0) {
        return false;
    }
    const weeklyRemainingPercent = 100 - (usage.weeklyUsedPercent ?? 0);
    const maxAllowedPercent = codexLimits.weekly.percentage;
    return weeklyRemainingPercent < maxAllowedPercent && isCodexModel(lowerModelId);
}

function checkCodexDailyLimit(usage: { dailyLimit?: number; dailyUsedPercent?: number }, codexLimits: { daily?: { enabled?: boolean; percentage: number } } | undefined, lowerModelId: string) {
    if (!codexLimits?.daily?.enabled || usage.dailyLimit === undefined || usage.dailyLimit <= 0) {
        return false;
    }
    const dailyRemainingPercent = 100 - (usage.dailyUsedPercent ?? 0);
    const maxAllowedPercent = codexLimits.daily.percentage;
    return dailyRemainingPercent < maxAllowedPercent && isCodexModel(lowerModelId);
}

function findAntigravityQuotaModel(quotas: { accounts: QuotaResponse[] }, lowerModelId: string, modelId: string) {
    const foundQuota = quotas.accounts.find(a => a.models.some((m) => m.id.toLowerCase() === lowerModelId));
    if (!foundQuota) { return null; }

    return foundQuota.models.find((m) =>
        m.id.toLowerCase() === lowerModelId || m.id.toLowerCase() === modelId.toLowerCase()
    );
}

function checkAntigravityUserDefinedLimit(modelId: string, lowerModelId: string, quotas: { accounts: QuotaResponse[] } | null, settings?: AppSettings) {
    if (!quotas) { return false; }
    const antigravityLimits = settings?.modelUsageLimits?.antigravity;
    const modelLimit = antigravityLimits?.[modelId] ?? antigravityLimits?.[lowerModelId];

    if (!modelLimit?.enabled) { return false; }

    const modelQuotaItem = findAntigravityQuotaModel(quotas, lowerModelId, modelId);
    if (!modelQuotaItem) { return false; }

    return modelQuotaItem.percentage < modelLimit.percentage;
}

function checkAntigravityGeneralQuota(modelId: string, lowerModelId: string, quotas: { accounts: QuotaResponse[] } | null) {
    if (!quotas) { return false; }

    const modelQuotaItem = findAntigravityQuotaModel(quotas, lowerModelId, modelId);
    if (!modelQuotaItem) { return false; }

    return modelQuotaItem.percentage <= 5;
}

function isGroupQuotaExhausted(gQuota: Record<string, unknown> | { exhausted?: boolean; remaining: number; percentage?: number }): boolean {
    const quotaData = gQuota as unknown as Record<string, unknown>;
    if (quotaData.percentage !== undefined && typeof quotaData.percentage === 'number' && quotaData.percentage <= 5) {
        return true;
    }

    const q = gQuota as { exhausted?: boolean; remaining: number };
    if (q.exhausted ?? q.remaining <= 0) {
        return true;
    }

    return false;
}

function checkAntigravityGroupQuota(lowerModelId: string, agQuota: Record<string, { exhausted?: boolean; remaining: number; percentage?: number }>) {
    for (const [, groupModels] of Object.entries(ANTIGRAVITY_QUOTA_GROUPS)) {
        if (!groupModels.some(m => m.toLowerCase() === lowerModelId)) { continue; }

        for (const groupModel of groupModels) {
            if (!(groupModel in agQuota) && !(groupModel.toLowerCase() in agQuota)) { continue; }
            const gQuota = agQuota[groupModel] ?? agQuota[groupModel.toLowerCase()];

            if (isGroupQuotaExhausted(gQuota)) { return true; }
        }
        return false; // Should break/return if found group? Original code broke after first matching group.
    }
    return false;
}

function checkAntigravitySpecificQuota(modelId: string, lowerModelId: string, agQuota: Record<string, { exhausted?: boolean; remaining: number; percentage?: number }>) {
    const hasModelQuota = modelId in agQuota || lowerModelId in agQuota;
    if (!hasModelQuota) { return false; }

    const modelQuota = agQuota[modelId] ?? agQuota[lowerModelId];
    if (modelQuota.percentage !== undefined && modelQuota.percentage <= 5) { return true; }
    if (modelQuota.exhausted ?? modelQuota.remaining <= 0) { return true; }
    return false;
}

function checkCodexUsageStatus(codexAccount: { usage: CodexUsage }, lowerModelId: string, settings?: AppSettings) {
    const usage = codexAccount.usage;
    const codexLimits = settings?.modelUsageLimits?.codex;

    if (checkCodexWeeklyLimit(usage, codexLimits, lowerModelId)) { return true; }
    if (checkCodexDailyLimit(usage, codexLimits, lowerModelId)) { return true; }

    if (!isCodexModel(lowerModelId)) { return false; }

    if (usage.weeklyLimit === 0) { return true; }
    if ((usage.dailyUsedPercent ?? 0) >= 100) { return true; }

    return false;
}

function isOpenAIProvider(p: string) {
    return p === 'codex' || p === 'openai';
}

function isClaudeProvider(p: string) {
    return p === 'claude' || p === 'anthropic';
}

export function useModelSelectorLogic({
    settings,
    groupedModels,
    quotas,
    codexUsage,
    claudeQuota
}: UseModelSelectorLogicProps) {
    const [usageLimitChecks, setUsageLimitChecks] = useState<Record<string, { allowed: boolean; reason?: string }>>({});

    useEffect(() => {
        if (!settings?.modelUsageLimits) { return; }
        const checkLimits = async () => {
            const checks: Record<string, { allowed: boolean; reason?: string }> = {};
            if (groupedModels) {
                for (const [provider, group] of Object.entries(groupedModels)) {
                    for (const model of group.models) {
                        const modelId = model.id ?? '';
                        if (!modelId) { continue; }
                        const key = `${provider}:${modelId}`;
                        try {
                            const result = await window.electron.checkUsageLimit(provider, modelId);
                            checks[key] = result;
                        } catch {
                            checks[key] = { allowed: true };
                        }
                    }
                }
            }
            setUsageLimitChecks(checks);
        };
        void checkLimits();
    }, [settings?.modelUsageLimits, groupedModels]);

    const isCodexDisabled = useCallback((_modelId: string, lowerModelId: string) => {
        const codexAccount = codexUsage?.accounts[0];
        if (!codexAccount) { return false; }
        return checkCodexUsageStatus(codexAccount, lowerModelId, settings);
    }, [codexUsage, settings]);

    const isCopilotDisabled = useCallback(() => {
        if (!quotas) { return false; }
        const copilotQuota = quotas.accounts.find(a => a.copilot)?.copilot;
        if (copilotQuota) {
            const q = copilotQuota as { remaining: number; limit: number };
            if (q.remaining <= 5 && q.limit > 0) { return true; }
        }
        return false;
    }, [quotas]);

    const isClaudeDisabled = useCallback(() => {
        const UTILIZATION_THRESHOLD = 99; // 99% = effectively exhausted

        const checkClaudeQuotaExhausted = (quota: ClaudeQuota): boolean => {
            const now = Date.now();

            // Check if 5-hour quota is exhausted
            const fiveHourExhausted = quota.fiveHour && quota.fiveHour.utilization >= UTILIZATION_THRESHOLD;
            const fiveHourResetPassed = quota.fiveHour?.resetsAt ? new Date(quota.fiveHour.resetsAt).getTime() <= now : false;

            // Check if 7-day quota is exhausted
            const sevenDayExhausted = quota.sevenDay && quota.sevenDay.utilization >= UTILIZATION_THRESHOLD;
            const sevenDayResetPassed = quota.sevenDay?.resetsAt ? new Date(quota.sevenDay.resetsAt).getTime() <= now : false;

            // If 7-day quota is exhausted and reset hasn't passed, model is disabled
            if (sevenDayExhausted && !sevenDayResetPassed) {
                return true;
            }

            // If 5-hour quota is exhausted but reset has passed, model is available
            if (fiveHourExhausted && fiveHourResetPassed) {
                return false;
            }

            // If 5-hour quota is exhausted and reset hasn't passed, disabled until reset
            if (fiveHourExhausted && !fiveHourResetPassed) {
                return true;
            }

            return false;
        };

        // First check dedicated claudeQuota prop (preferred source)
        if (claudeQuota?.accounts && claudeQuota.accounts.length > 0) {
            for (const quota of claudeQuota.accounts) {
                if (checkClaudeQuotaExhausted(quota)) {
                    return true;
                }
            }
        }
        // Fallback: check claudeQuota embedded in quotas.accounts
        if (quotas?.accounts) {
            const embeddedQuota = quotas.accounts.find(a => a.claudeQuota)?.claudeQuota;
            if (embeddedQuota && checkClaudeQuotaExhausted(embeddedQuota as ClaudeQuota)) {
                return true;
            }
        }
        return false;
    }, [claudeQuota, quotas]);

    const isAntigravityDisabled = useCallback((modelId: string, lowerModelId: string) => {
        if (!quotas) { return false; }
        if (checkAntigravityUserDefinedLimit(modelId, lowerModelId, quotas, settings)) { return true; }
        if (checkAntigravityGeneralQuota(modelId, lowerModelId, quotas)) { return true; }

        const agAccount = quotas.accounts.find(a => 'antigravity' in a);
        const agQuota = agAccount && 'antigravity' in agAccount ? (agAccount as Record<string, unknown>).antigravity as Record<string, { exhausted?: boolean; remaining: number; percentage?: number }> | undefined : undefined;

        if (agQuota) {
            if (checkAntigravitySpecificQuota(modelId, lowerModelId, agQuota)) { return true; }
            if (checkAntigravityGroupQuota(lowerModelId, agQuota)) { return true; }
        }
        return false;
    }, [quotas, settings]);

    const isProviderSpecificDisabled = useCallback((p: string, modelId: string, lowerModelId: string) => {
        if (isOpenAIProvider(p)) { return isCodexDisabled(modelId, lowerModelId); }
        if (p === 'copilot') { return isCopilotDisabled(); }
        if (isClaudeProvider(p)) { return isClaudeDisabled(); }
        if (p === 'antigravity') { return isAntigravityDisabled(modelId, lowerModelId); }
        if (['local', 'lm_studio', 'ollama', 'gemini'].includes(p)) { return false; }
        return false;
    }, [isCodexDisabled, isCopilotDisabled, isClaudeDisabled, isAntigravityDisabled]);

    // handleModelChange removed as unused

    const isModelDisabled = useCallback((modelId: string, provider: string) => {
        const p = provider.toLowerCase();
        const lowerModelId = modelId.toLowerCase();

        // Check generic usage limits if enabled
        const limitKey = `${provider}:${modelId}`;
        if (limitKey in usageLimitChecks && !usageLimitChecks[limitKey].allowed) { return true; }

        return isProviderSpecificDisabled(p, modelId, lowerModelId);
    }, [usageLimitChecks, isProviderSpecificDisabled]);

    return { isModelDisabled };
}

