export type ModelProvider = 'copilot' | 'openai' | 'codex' | 'anthropic' | 'ollama' | 'antigravity' | 'opencode' | 'nvidia' | 'custom';

const VALID_PROVIDERS: Set<string> = new Set(['copilot', 'openai', 'codex', 'anthropic', 'ollama', 'antigravity', 'opencode', 'nvidia', 'github']);

export interface ModelDefinition {
    id: string;
    label: string;
    provider: ModelProvider;
    family?: string;
    type?: 'chat' | 'image' | 'video';
}

/**
 * Pure dynamic categorization. 
 * STRICTLY respects the providerHint if it's a known provider.
 */
export function categorizeModel(modelId: string, providerHint?: string): ModelDefinition {
    const lower = modelId.toLowerCase();

    const hint = providerHint?.toLowerCase();

    const type = detectModelType(lower);

    // STRICT: If hint is a known provider, use it directly. No heuristics.
    if (hint && VALID_PROVIDERS.has(hint)) {
        return createDefinition(modelId, hint as ModelProvider, type);
    }

    // Fallback Heuristics
    const provider = detectProvider(lower);
    return createDefinition(modelId, provider, type);
}

function detectModelType(lowerId: string): 'chat' | 'image' | 'video' {
    if (lowerId.includes('image') || lowerId.includes('imagen') || lowerId.includes('dalle') || lowerId.includes('stable-diffusion') || lowerId.includes('flux')) {
        return 'image';
    }
    if (lowerId.includes('video') || lowerId.includes('sora') || lowerId.includes('kling')) {
        return 'video';
    }
    return 'chat';
}

function detectProvider(lowerId: string): ModelProvider {
    if (lowerId.includes('codex') || lowerId.startsWith('gpt-5') || lowerId.startsWith('o1') || lowerId.startsWith('o3')) {
        return 'codex';
    }
    if (lowerId.includes('gpt-')) {
        return 'openai';
    }
    if (lowerId.startsWith('copilot-') || lowerId.startsWith('github-')) {
        return 'copilot';
    }
    if (lowerId.startsWith('claude-') || lowerId.includes('anthropic/')) {
        return 'anthropic';
    }
    if (lowerId.startsWith('opencode-')) {
        return 'opencode';
    }
    if (lowerId.includes('nvidia/')) {
        return 'nvidia';
    }
    return 'custom';
}

function createDefinition(id: string, provider: ModelProvider, type: 'chat' | 'image' | 'video'): ModelDefinition {
    return {
        id,
        label: formatLabel(id),
        provider,
        type
    };
}

function formatLabel(slug: string): string {
    let label = slug.replace(/^(github-|copilot-|openai-|codex-|antigravity-|ollama-|opencode-|nvidia-|nvidia\/|google\/|meta\/|mistralai\/|microsoft\/|deepseek-ai\/)/i, '');

    // If ID contains multiple slashes or segments, take the last part
    if (label.includes('/')) {
        const parts = label.split('/');
        label = parts[parts.length - 1] ?? label;
    }

    return label
        .split(/[-_]/)
        .map(word => {
            const low = word.toLowerCase();
            if (['gpt', 'llm', 'ai', 'o1', 'r1', 'v3'].includes(low)) { return word.toUpperCase(); }
            if (/^\d/.test(word)) { return word; }
            return word.charAt(0).toUpperCase() + word.slice(1);
        })
        .join(' ');
}

import { X } from 'lucide-react';
import React, { useState } from 'react';

import { Modal } from '@/components/ui/modal';
import { useAuth } from '@/context/AuthContext';
import { useTranslation } from '@/i18n';
import { AnimatePresence, motion } from '@/lib/framer-motion-compat';
import { cn } from '@/lib/utils';

interface OnboardingFlowProps {
    isOpen: boolean;
    onClose: () => void;
    onStartTour?: () => void;
}

const STEPS = [
    {
        title: 'welcome',
        icon: '🏮',
        color: 'from-orange-500 to-red-600',
    },
    {
        title: 'multiModel',
        icon: '🧠',
        color: 'from-blue-500 to-indigo-600',
    },
    {
        title: 'workspace',
        icon: '🚀',
        color: 'from-emerald-500 to-teal-600',
    },
    {
        title: 'privacy',
        icon: '🛡️',
        color: 'from-purple-500 to-pink-600',
    }
];

export const OnboardingFlow: React.FC<OnboardingFlowProps> = ({ isOpen, onClose, onStartTour }) => {
    const [currentStep, setCurrentStep] = useState(0);
    const { language } = useAuth();
    const { t } = useTranslation(language);

    const completeOnboarding = () => {
        localStorage.setItem('Tandem-onboarding-complete', 'true');
        // Also update via IPC if available
        window.electron?.ipcRenderer?.invoke?.('settings:update', {
            general: { onboardingCompleted: true }
        }).catch(() => { /* Settings update is optional */ });
        onClose();
    };

    const handleNext = () => {
        if (currentStep < STEPS.length - 1) {
            setCurrentStep(prev => prev + 1);
        } else {
            completeOnboarding();
            // Optionally start the detailed tour
            onStartTour?.();
        }
    };

    const handleSkip = () => {
        completeOnboarding();
    };

    const handleBack = () => {
        if (currentStep > 0) {
            setCurrentStep(prev => prev - 1);
        }
    };

    const step = STEPS[currentStep];
    // Use camelCase keys: welcome -> welcomeTitle, welcomeDescription
    const titleKey = `onboarding.${step.title}Title` as const;
    const descKey = `onboarding.${step.title}Description` as const;

    return (
        <Modal
            isOpen={isOpen}
            onClose={onClose}
            title={t(titleKey)}
            className="max-w-2xl"
        >
            <div className="relative overflow-hidden min-h-[350px] flex flex-col">
                {/* Skip button */}
                <button
                    onClick={handleSkip}
                    className="absolute top-0 right-0 p-2 text-muted-foreground hover:text-foreground hover:bg-muted/30 rounded-lg transition-all z-10"
                    title={t('onboarding.skip')}
                >
                    <X className="w-5 h-5" />
                </button>

                {/* Progress bar */}
                <div className="flex gap-1 mb-8 pr-8">
                    {STEPS.map((_, i) => (
                        <div
                            key={i}
                            className={cn(
                                "h-1.5 flex-1 rounded-full transition-all duration-500",
                                i <= currentStep ? "bg-primary" : "bg-muted"
                            )}
                        />
                    ))}
                </div>

                <AnimatePresence mode="wait">
                    <motion.div
                        key={currentStep}
                        initial={{ x: 20, opacity: 0 }}
                        animate={{ x: 0, opacity: 1 }}
                        exit={{ x: -20, opacity: 0 }}
                        transition={{ duration: 0.3, ease: "easeInOut" }}
                        className="flex-1 flex flex-col items-center text-center space-y-6"
                    >
                        <div className={cn(
                            "w-24 h-24 rounded-3xl bg-gradient-to-br flex items-center justify-center text-5xl shadow-2xl",
                            step.color
                        )}>
                            {step.icon}
                        </div>

                        <div className="space-y-4">
                            <h2 className="text-2xl font-black tracking-tight text-foreground">
                                {t(titleKey)}
                            </h2>
                            <p className="text-muted-foreground text-lg leading-relaxed max-w-md mx-auto">
                                {t(descKey)}
                            </p>
                        </div>
                    </motion.div>
                </AnimatePresence>

                <div className="mt-auto flex justify-between items-center pt-8 border-t border-border/50">
                    <button
                        onClick={handleBack}
                        className={cn(
                            "px-6 py-2 rounded-xl text-sm font-semibold transition-all",
                            currentStep === 0 ? "opacity-0 pointer-events-none" : "hover:bg-muted text-muted-foreground"
                        )}
                    >
                        {t('common.back')}
                    </button>

                    <button
                        onClick={handleNext}
                        className="px-8 py-3 rounded-xl bg-primary text-primary-foreground font-bold text-sm shadow-lg shadow-primary/20 hover:scale-[1.02] active:scale-95 transition-all"
                    >
                        {currentStep === STEPS.length - 1 ? t('common.getStarted') : t('common.next')}
                    </button>
                </div>
            </div>
        </Modal>
    );
};

