                            onClick={() => onAddNode('planner')}
                            className="w-full flex items-center gap-2 px-2 py-1.5 hover:bg-white/10 rounded-lg text-sm transition-colors text-left"
                        >
                            <Sparkles className="w-4 h-4 text-purple-400" />
