export type TaskNodeData = {
    label: string;
    taskType?: 'planner' | 'action';
    status?: 'idle' | 'planning' | 'waiting_for_approval' | 'running' | 'completed' | 'failed' | 'waiting' | 'error';
    description?: string;
    title?: string;
    model?: { provider: string; model: string };
    projectId?: string;
    attachments?: Array<{ name: string; path: string; size: number }>;
    plan?: ProjectStep[];
    history?: Message[];
    activeTab?: 'plan' | 'logs';
    isExpanded?: boolean;
    isModelOpen?: boolean;
    systemMode?: 'thinking' | 'fast' | 'architect';
    agentProfileId?: string;
    /** Total token usage */
    totalTokens?: ProjectState['totalTokens'];
    /** Task timing */
    timing?: ProjectState['timing'];
};

interface TaskNodeActionProps {
    id: string;
    data: TaskNodeData;
    updateNodeData: (id: string, data: Partial<TaskNodeData>) => void;
    currentProviderId: string;
    currentModelId: string;
    selectedProjectId?: string;
}

const useTaskNodeActions = ({ id, data, updateNodeData, currentProviderId, currentModelId, selectedProjectId }: TaskNodeActionProps) => {
    const { t } = useLanguage();
    const planInFlightRef = useRef(false);
    const executeInFlightRef = useRef(false);

    const handlePlan = useCallback(async () => {
        if (!data.title && !data.description) {
            return;
        }
        if (planInFlightRef.current) {
            appLogger.warn('TaskNode', 'Plan request ignored because a previous plan request is still in-flight');
            return;
        }

        planInFlightRef.current = true;
        try {
            updateNodeData(id, { status: 'planning', isExpanded: true });
            const options: AgentStartOptions = {
                task: data.title ?? data.description ?? t('projectAgent.newTask'),
                nodeId: id,
                model: { provider: currentProviderId, model: currentModelId },
                projectId: selectedProjectId,
                attachments: data.attachments,
                systemMode: data.systemMode,
                agentProfileId: data.agentProfileId
            };
            await window.electron.projectAgent.generatePlan(options);
        } catch (error) {
            const message = error instanceof Error ? error.message : String(error);
            if (message.includes('Cannot start planning from current state: planning')) {
                appLogger.warn('TaskNode', 'Plan request blocked: another planning session is already active');
                updateNodeData(id, { status: 'idle' });
                return;
            }
            appLogger.error('TaskNode', 'Failed to generate plan', error as Error);
            updateNodeData(id, { status: 'failed' });
        } finally {
            planInFlightRef.current = false;
        }
    }, [data.title, data.description, data.attachments, data.systemMode, data.agentProfileId, currentProviderId, currentModelId, selectedProjectId, id, updateNodeData, t, planInFlightRef]);

    const handleApprove = useCallback(async () => {
        if (!data.plan) {
            return;
        }
        try {
            updateNodeData(id, { status: 'running' });
            await window.electron.projectAgent.approvePlan(data.plan);
        } catch (error) {
            appLogger.error('TaskNode', 'Failed to approve plan', error as Error);
            updateNodeData(id, { status: 'failed' });
        }
    }, [data.plan, id, updateNodeData]);

    const handleExecute = useCallback(async () => {
        if (!data.title && !data.description) {
            return;
        }
        if (executeInFlightRef.current) {
            appLogger.warn('TaskNode', 'Execute request ignored because a previous execute request is still in-flight');
            return;
        }
        executeInFlightRef.current = true;
        try {
            updateNodeData(id, { status: 'running', activeTab: 'logs' });
            const options: AgentStartOptions = {
                task: data.title ?? data.description ?? t('projectAgent.newTask'),
                nodeId: id,
                model: { provider: currentProviderId, model: currentModelId },
                projectId: selectedProjectId,
                attachments: data.attachments,
                systemMode: data.systemMode,
                agentProfileId: data.agentProfileId
            };
            await window.electron.projectAgent.start(options);
        } catch (error) {
            appLogger.error('TaskNode', 'Failed to start task', error as Error);
            updateNodeData(id, { status: 'failed' });
        } finally {
            executeInFlightRef.current = false;
        }
    }, [data.title, data.description, data.attachments, data.systemMode, data.agentProfileId, currentProviderId, currentModelId, selectedProjectId, id, updateNodeData, t, executeInFlightRef]);

    const handleStop = useCallback(async () => {
        try {
            updateNodeData(id, { status: 'waiting' });
            await window.electron.projectAgent.stop();
        } catch (error) {
            appLogger.error('TaskNode', 'Failed to stop task', error as Error);
        }
    }, [id, updateNodeData]);

    const handleRetryStep = useCallback(async (index: number) => {
        try {
            updateNodeData(id, { status: 'running', activeTab: 'logs' });
            await window.electron.projectAgent.retryStep(index);
        } catch (error) {
            appLogger.error('TaskNode', 'Failed to retry step', error as Error);
            updateNodeData(id, { status: 'failed' });
        }
    }, [id, updateNodeData]);

    return { handlePlan, handleApprove, handleExecute, handleStop, handleRetryStep };
};

interface TaskNodeStateProps {
    id: string;
    data: TaskNodeData;
    projects: Project[];
    globalSelectedProject: Project | null;
    globalModelId: string;
    globalProviderId: string;
    updateNodeData: (id: string, data: Partial<TaskNodeData>) => void;
}

const useTaskExpandedLogs = (id: string, status?: string, updateNodeData?: (id: string, data: Partial<TaskNodeData>) => void) => {
    const hasSwitchedToLogs = useRef(false);

    useEffect(() => {
        if (status === 'running' && !hasSwitchedToLogs.current) {
            const timer = setTimeout(() => {
                updateNodeData?.(id, { activeTab: 'logs', isExpanded: true });
                hasSwitchedToLogs.current = true;
            }, 100);
            return () => clearTimeout(timer);
        } else if (status !== 'running') {
            hasSwitchedToLogs.current = false;
        }
        return undefined;
    }, [status, id, updateNodeData]);
};

const getSelectedProjectId = (
    data: TaskNodeData,
    globalSelectedProject: Project | null,
    projects: Project[]
) => {
    if (data.projectId) {
        return data.projectId;
    }
    if (globalSelectedProject?.id) {
        return globalSelectedProject.id;
    }
    return projects.length > 0 ? projects[0].id : undefined;
};

const useTaskNodeState = ({
    id,
    data,
    projects,
    globalSelectedProject,
    globalModelId,
    globalProviderId,
    updateNodeData
}: TaskNodeStateProps) => {
    const activeTab = data.activeTab ?? 'plan';
    const isExpanded = data.isExpanded ?? true;
    const isModelOpen = data.isModelOpen ?? false;

    useTaskExpandedLogs(id, data.status, updateNodeData);

    const isPlanner = data.taskType === 'planner';
    const isAction = data.taskType === 'action';
    const selectedProjectId = getSelectedProjectId(data, globalSelectedProject, projects);
    const selectedProject = projects.find(p => p.id === selectedProjectId);
    const currentModelId = data.model?.model ?? globalModelId;
    const currentProviderId = data.model?.provider ?? globalProviderId;

    return { activeTab, isExpanded, isModelOpen, isPlanner, isAction, selectedProjectId, selectedProject, currentModelId, currentProviderId };
};

// --- Sub-components ---

/**
 * Format token count to human-readable (1.2k, 5.5k, etc.)
 */
const formatTokens = (count: number): string => {
    if (count >= 1000) {
        return `${(count / 1000).toFixed(1)}k`;
    }
    return String(count);
};

/**
 * Format milliseconds to human-readable duration
 */
const formatDuration = (ms: number): string => {
    if (ms < 1000) {
        return `${ms}ms`;
    }
    if (ms < 60000) {
        return `${(ms / 1000).toFixed(1)}s`;
    }
    const mins = Math.floor(ms / 60000);
    const secs = Math.floor((ms % 60000) / 1000);
    return `${mins}m ${secs}s`;
};

/**
 * TokenCounter - Displays token usage for a step or total
 */
const TokenCounter = ({ tokens, timing, className }: {
    tokens?: { prompt: number; completion: number };
    timing?: { durationMs?: number };
    className?: string;
}) => {
    if (!tokens && !timing?.durationMs) {
        return null;
    }

    const total = (tokens?.prompt ?? 0) + (tokens?.completion ?? 0);

    return (
        <div className={cn("flex items-center gap-2 text-xxs text-muted-foreground", className)}>
            {tokens && total > 0 && (
                <span className="flex items-center gap-1" title={`${tokens.prompt} prompt + ${tokens.completion} completion`}>
                    <Coins className="w-3 h-3" />
                    {formatTokens(total)}
                </span>
            )}
            {timing?.durationMs && timing.durationMs > 0 && (
                <span className="flex items-center gap-1">
                    <Clock className="w-3 h-3" />
                    {formatDuration(timing.durationMs)}
                </span>
            )}
        </div>
    );
};

/**
 * ProgressRing - SVG circular progress indicator around an icon
 */
const ProgressRing = ({ progress, size = 32, strokeWidth = 2, className, children }: {
    progress: number;
    size?: number;
    strokeWidth?: number;
    className?: string;
    children: React.ReactNode;
}) => {
    const radius = (size - strokeWidth) / 2;
    const circumference = radius * 2 * Math.PI;
    const strokeDashoffset = circumference - (progress / 100) * circumference;

    return (
        <div className={cn("relative inline-flex items-center justify-center", className)} style={{ width: size, height: size }}>
            <svg className="absolute -rotate-90" width={size} height={size}>
                {/* Background ring */}
                <circle
                    className="text-muted/30"
                    strokeWidth={strokeWidth}
                    stroke="currentColor"
                    fill="transparent"
                    r={radius}
                    cx={size / 2}
                    cy={size / 2}
                />
                {/* Progress ring */}
                <circle
                    className="text-primary transition-all duration-500 ease-out"
                    strokeWidth={strokeWidth}
                    strokeDasharray={circumference}
                    strokeDashoffset={strokeDashoffset}
                    strokeLinecap="round"
                    stroke="currentColor"
                    fill="transparent"
                    r={radius}
                    cx={size / 2}
                    cy={size / 2}
                />
            </svg>
            <div className="z-10">{children}</div>
        </div>
    );
};

const TaskMetaInfo = ({ status }: { status: string }) => {
    if (status !== 'running' && status !== 'planning') {
        return null;
    }
    return (
        <div className="h-1 w-full bg-muted rounded-full overflow-hidden">
