interface TaskBodyProps {
    id: string;
    data: TaskNodeData;
    isPlanner: boolean;
    isAction: boolean;
    isExpanded: boolean;
    activeTab: 'plan' | 'logs';
    updateNodeData: (id: string, data: Partial<TaskNodeData>) => void;
    onRetry: (index: number) => void | Promise<void>;
    planContainerRef: React.RefObject<HTMLDivElement>;
    activeStepRef: React.RefObject<HTMLDivElement>;
}

const TaskInput = ({
    id, data, updateNodeData
}: { id: string; data: TaskNodeData; updateNodeData: (id: string, data: Partial<TaskNodeData>) => void }) => {
    const { t } = useLanguage();
    const removeAttachment = (index: number) => {
        const newAttachments = [...(data.attachments ?? [])];
        newAttachments.splice(index, 1);
        updateNodeData(id, { attachments: newAttachments });
    };

    return (
        <div className="space-y-2">
            <input
                className="w-full bg-transparent border-none p-0 text-sm font-semibold focus:outline-none focus:ring-0"
                placeholder={t('tools.taskTitlePlaceholder')}
                value={data.title ?? ''}
                onChange={(e) => updateNodeData(id, { title: e.target.value })}
            />
            {data.attachments && data.attachments.length > 0 && (
                <div className="flex flex-wrap gap-1.5 mb-2">
                    {data.attachments.map((file, idx) => (
                        <div key={idx} className="flex items-center gap-1 bg-muted/20 px-2 py-1 rounded-md text-xxs text-muted-foreground border border-border/20 group/file">
                            <span className="truncate max-w-[100px]">{file.name}</span>
                            <button onClick={() => removeAttachment(idx)} className="hover:text-destructive opacity-0 group-hover/file:opacity-100 transition-opacity">
                                <X className="w-3 h-3" />
                            </button>
                        </div>
                    ))}
                </div>
            )}
            <textarea
                className="w-full bg-card/20 border border-border/20 rounded-md p-2 text-xs focus:outline-none focus:border-primary/50 resize-none nodrag"
                placeholder={t('tools.taskDescriptionPlaceholder')}
                rows={3}
                value={data.description ?? ''}
                onChange={(e) => updateNodeData(id, { description: e.target.value })}
            />
        </div>
    );
};

const TaskBody = ({
    id, data, isPlanner, isAction, isExpanded, activeTab, updateNodeData, onRetry, planContainerRef, activeStepRef
}: TaskBodyProps) => {
    const { t } = useLanguage();

    // Debug: Log render conditions
    appLogger.debug('TaskBody', `Node ${id}: isExpanded=${isExpanded}, isPlanner=${isPlanner}, taskType=${data.taskType}, plan=${data.plan?.length ?? 0}, status=${data.status}`);

    return (
        <div className="p-4 space-y-3">
            {isPlanner ? (
                <TaskInput id={id} data={data} updateNodeData={updateNodeData} />
            ) : isAction ? (
                <div className="bg-card/20 border border-border/20 rounded-md p-2 text-xs text-muted-foreground">
                    {t('projectAgent.selectAction')}
                </div>
            ) : (
                <p className="text-xs text-muted-foreground leading-relaxed line-clamp-2">
                    {data.description ?? t('projectAgent.noDescription')}
                </p>
            )}
            {isPlanner && data.plan && data.plan.length > 0 && <ProgressBar plan={data.plan} totalTokens={data.totalTokens} />}
            {isExpanded && isPlanner && (
                <TaskExecutionDetails
                    id={id}
                    data={data}
                    activeTab={activeTab}
                    updateNodeData={updateNodeData}
                    onRetry={onRetry}
                    planContainerRef={planContainerRef}
                    activeStepRef={activeStepRef}
                    t={t}
                />
            )}
            <TaskMetaInfo status={data.status ?? 'idle'} />
        </div>
    );
};

const getTaskNodeClasses = (isExpanded: boolean, selected: boolean, status: string) => {
    return cn(
        "bg-card/90 backdrop-blur-xl border-2 rounded-xl transition-all duration-300 group shadow-lg",
        isExpanded ? "w-[500px]" : "w-72",
        selected ? "border-primary shadow-primary/20 scale-[1.02]" : "border-border/50 hover:border-primary/50",
        status === 'running' && "border-info shadow-info/20 animate-pulse",
        status === 'planning' && "border-primary shadow-primary/20 animate-pulse",
        status === 'waiting_for_approval' && "border-warning shadow-warning/20",
        status === 'completed' && "border-success shadow-success/20",
        status === 'failed' && "border-destructive shadow-destructive/20"
    );
};

export const TaskNode = ({ id, data, selected }: NodeProps<Node<TaskNodeData>>) => {
    const { updateNodeData, deleteElements } = useReactFlow();
    const { projects, selectedProject: globalSelectedProject } = useProjectManager();
    const { groupedModels, selectedModel: globalModelId, selectedProvider: globalProviderId } = useModel();
    const [profiles, setProfiles] = React.useState<AgentProfile[]>([]);

    useEffect(() => {
        const fetchProfiles = async () => {
            try {
                const getProfilesFn = (window.electron.projectAgent as { getProfiles?: () => Promise<AgentProfile[]> } | undefined)?.getProfiles;
                if (typeof getProfilesFn !== 'function') {
                    appLogger.warn('TaskNode', 'projectAgent.getProfiles is unavailable in current preload bridge');
                    setProfiles([]);
                    return;
                }

                const fetched = await getProfilesFn();
                setProfiles(fetched);
            } catch (err) {
                appLogger.error('TaskNode', 'Failed to fetch agent profiles', err as Error);
            }
        };
        void fetchProfiles();
    }, []);

    const {
        activeTab, isExpanded, isModelOpen, isPlanner, isAction,
        selectedProjectId, selectedProject, currentModelId, currentProviderId
    } = useTaskNodeState({ id, data, projects, globalSelectedProject, globalModelId, globalProviderId, updateNodeData });

    const { handlePlan, handleApprove, handleExecute, handleStop, handleRetryStep } = useTaskNodeActions({ id, data, updateNodeData, currentProviderId, currentModelId, selectedProjectId });

    const fileInputRef = useRef<HTMLInputElement>(null);
    const planContainerRef = useRef<HTMLDivElement>(null);
    const activeStepRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        const runningStepId = data.plan?.find(s => s.status === 'running')?.id;
        if (runningStepId && activeStepRef.current && planContainerRef.current) {
            activeStepRef.current.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
        }
    }, [data.plan]);

    useEffect(() => {
        const status = data.status ?? 'idle';
        const needsExpansion = ['planning', 'waiting_for_approval'].includes(status);
        if (needsExpansion) {
            // When waiting for approval, expand the node and show plan tab
            const updates: Partial<TaskNodeData> = { isExpanded: true };
            if (status === 'waiting_for_approval') {
                updates.activeTab = 'plan';
            }
            updateNodeData(id, updates);
        }
    }, [data.status, id, updateNodeData]);

    // Ensure ?? is used instead of || where appropriate for linting
    // Removed unused nodeStatus

    const onFileChange = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files && e.target.files.length > 0) {
            const files = Array.from(e.target.files);
            const newAttachments = files.map(f => ({
                name: f.name,
                path: (f as { path?: string }).path ?? f.name,
                size: f.size
            }));
            updateNodeData(id, { attachments: [...(data.attachments ?? []), ...newAttachments] });
        }
    }, [id, data.attachments, updateNodeData]);

    // Calculate plan progress percentage
    const planProgress = React.useMemo(() => {
        if (!data.plan || data.plan.length === 0) {
            return 0;
        }
        const completed = data.plan.filter(s => s.status === 'completed').length;
        return Math.round((completed / data.plan.length) * 100);
    }, [data.plan]);

    return (
        <div className={getTaskNodeClasses(isExpanded, !!selected, data.status ?? 'idle')}>
            <Handle type="target" position={Position.Top} className="!w-3 !h-3 !bg-muted-foreground !border-2 !border-background transition-colors hover:!bg-primary" />
            <TaskHeader isPlanner={isPlanner} isAction={isAction} label={data.label} selectedProject={selectedProject} projects={projects} selectedProjectId={selectedProjectId} onProjectSelect={(pid) => updateNodeData(id, { projectId: pid })} isExpanded={isExpanded} setIsExpanded={(expanded) => updateNodeData(id, { isExpanded: expanded })} onDelete={() => void deleteElements({ nodes: [{ id }] })} progress={planProgress} status={data.status} />

            <TaskBody
                id={id}
                data={data}
                isPlanner={isPlanner}
                isAction={isAction}
                isExpanded={isExpanded}
                activeTab={activeTab}
                updateNodeData={updateNodeData}
                onRetry={handleRetryStep}
                planContainerRef={planContainerRef}
                activeStepRef={activeStepRef}
            />

            <TaskFooter
                isPlanner={isPlanner}
                status={data.status ?? 'idle'}
                isModelOpen={isModelOpen}
                currentProviderId={currentProviderId}
                currentModelId={currentModelId}
                groupedModels={groupedModels ?? undefined}
                onModelSelect={(provider, model) => void updateNodeData(id, { model: { provider, model } })}
                onOpenModelChange={(open) => void updateNodeData(id, { isModelOpen: open })}
                onFileClick={() => fileInputRef.current?.click()}
                onApprove={() => void handleApprove()}
                onStop={() => void handleStop()}
                onPlan={() => void handlePlan()}
                onExecute={() => void handleExecute()}
                canRun={!!(data.title ?? data.description)}
                systemMode={data.systemMode}
                onToggleThinking={() => updateNodeData(id, { systemMode: data.systemMode === 'thinking' ? 'fast' : 'thinking' })}
                profiles={profiles}
                selectedProfileId={data.agentProfileId}
                onProfileSelect={(pid) => updateNodeData(id, { agentProfileId: pid })}
            />
            <input type="file" multiple className="hidden" ref={fileInputRef} onChange={(e) => void onFileChange(e)} />
            <Handle type="source" position={Position.Bottom} className="!w-3 !h-3 !bg-muted-foreground !border-2 !border-background transition-colors hover:!bg-primary" />
        </div>
    );
};

﻿import { ChevronDown, ChevronRight } from 'lucide-react';
import { useCallback, useEffect, useRef, useState } from 'react';

import { useTranslation } from '@/i18n';
import { renderIcon } from '@/lib/file-icons';
import { cn } from '@/lib/utils';
import { appLogger } from '@/utils/renderer-logger';

interface FileNode {
    name: string
    path: string
    isDirectory: boolean
    children?: FileNode[]
}

// PERF-005-2: Directory listing cache with LRU eviction
const CACHE_MAX_SIZE = 100;
const CACHE_TTL_MS = 30000; // 30 seconds

interface CacheEntry {
    data: FileNode[];
    timestamp: number;
}

class DirectoryCache {
    private cache = new Map<string, CacheEntry>();

    get(path: string): FileNode[] | null {
        const entry = this.cache.get(path);
        if (!entry) { return null; }

        // Check if cache entry has expired
        if (Date.now() - entry.timestamp > CACHE_TTL_MS) {
            this.cache.delete(path);
            return null;
        }

        return entry.data;
    }

    set(path: string, data: FileNode[]): void {
        // LRU eviction: remove oldest entry if cache is full
        if (this.cache.size >= CACHE_MAX_SIZE) {
            const oldestKey = this.cache.keys().next().value;
            if (oldestKey) {
                this.cache.delete(oldestKey);
            }
        }

        this.cache.set(path, { data, timestamp: Date.now() });
    }

    invalidate(path: string): void {
        this.cache.delete(path);
    }

    clear(): void {
        this.cache.clear();
    }
}

// Singleton cache instance shared across all FileExplorer components
const directoryCache = new DirectoryCache();

interface FileExplorerProps {
    rootPath?: string
    onFileSelect?: (path: string) => void
    onFolderSelect?: (path: string) => void
}

const FileTreeItem = ({ node, depth = 0, onSelect, onFolderSelect }: { node: FileNode, depth?: number, onSelect: (path: string) => void, onFolderSelect?: (path: string) => void }) => {
    const { t } = useTranslation();
    const [isOpen, setIsOpen] = useState(false);
    const [children, setChildren] = useState<FileNode[]>([]);
    const [loading, setLoading] = useState(false);
    const toggleTimeoutRef = useRef<NodeJS.Timeout>();
    // CLEAN-002-1: Track mounted state to prevent state updates after unmount
    const isMountedRef = useRef(true);

    const handleToggle = useCallback(async (e: React.MouseEvent) => {
        e.stopPropagation();

        // Debounce rapid folder clicks (300ms)
        if (toggleTimeoutRef.current) {
            clearTimeout(toggleTimeoutRef.current);
        }

        toggleTimeoutRef.current = setTimeout(async () => {
            // CLEAN-002-1: Check if still mounted before proceeding
            if (!isMountedRef.current) {return;}

            if (node.isDirectory) {
                onFolderSelect?.(node.path);

                if (!isOpen && children.length === 0) {
                    // PERF-005-2: Check cache first before fetching from filesystem
                    const cachedNodes = directoryCache.get(node.path);
                    if (cachedNodes) {
                        setChildren(cachedNodes);
                        setIsOpen(true);
                        return;
                    }

                    setLoading(true);
                    try {
                        const response = await window.electron.files.listDirectory(node.path) as unknown as { success?: boolean; data?: Array<{ name: string; isDirectory: boolean }> } | Array<{ name: string; isDirectory: boolean }>;

                        // CLEAN-002-1: Check if still mounted after async operation
                        if (!isMountedRef.current) {return;}

                        // Handle ServiceResponse format: { success, data } or direct array
                        const files = ('data' in response && Array.isArray(response.data)) ? response.data : (Array.isArray(response) ? response : []);
                        const nodes: FileNode[] = files.map((f: { name: string; isDirectory: boolean }) => ({
                            name: f.name,
                            path: `${node.path}/${f.name}`.replace(/\/\//g, '/'),
                            isDirectory: f.isDirectory
                        })).sort((a: FileNode, b: FileNode) => {
                            if (a.isDirectory === b.isDirectory) { return a.name.localeCompare(b.name); }
                            return a.isDirectory ? -1 : 1;
                        });

                        // PERF-005-2: Cache the directory listing
                        directoryCache.set(node.path, nodes);

                        setChildren(nodes);
                        setIsOpen(true);
                    } catch (error) {
                        // CLEAN-002-1: Only log error if still mounted
                        if (isMountedRef.current) {
                            appLogger.error('FileExplorer', 'Failed to load directory', error as Error);
                        }
                    } finally {
                        // CLEAN-002-1: Only update loading state if still mounted
                        if (isMountedRef.current) {
                            setLoading(false);
                        }
                    }
                } else {
                    setIsOpen(!isOpen);
                }
            }
        }, 300); // 300ms debounce
    }, [node.path, node.isDirectory, isOpen, children.length, onFolderSelect]);

    // CLEAN-002-1: Cleanup timeout and track unmount
    useEffect(() => {
        isMountedRef.current = true;
        return () => {
            isMountedRef.current = false;
            if (toggleTimeoutRef.current) {
                clearTimeout(toggleTimeoutRef.current);
            }
        };
    }, []);

    // Use the new centralized file icons system
    const icon = renderIcon(node.name, node.isDirectory, isOpen, { size: 14 });

    return (
        <div>
            <div
                className={cn(
                    "flex items-center gap-1.5 py-1 px-2 hover:bg-accent/50 cursor-pointer select-none transition-colors rounded-sm",
                    "text-sm text-muted-foreground hover:text-foreground"
                )}
                style={{ paddingLeft: `${depth * 12 + 8}px` }}
                onClick={() => { void (async () => { await handleToggle({ stopPropagation: () => {} } as React.MouseEvent); })(); }}
            >
                <span className="opacity-70 w-4 flex justify-center">
                    {node.isDirectory && (
                        isOpen ? <ChevronDown size={12} /> : <ChevronRight size={12} />
                    )}
                </span>
                {icon}
                <span className="truncate">{node.name}</span>
            </div>
            {isOpen && (
                <div>
                    {loading ? (
                        <div className="pl-8 py-1 text-xs text-muted-foreground">{t('common.loading')}</div>
                    ) : (
                        children.map(child => (
                            <FileTreeItem key={child.path} node={child} depth={depth + 1} onSelect={onSelect} onFolderSelect={onFolderSelect} />
                        ))
                    )}
                </div>
            )}
        </div>
    );
};

export const FileExplorer = ({ rootPath, onFileSelect, onFolderSelect }: FileExplorerProps) => {
    const { t } = useTranslation();
    const [rootNodes, setRootNodes] = useState<FileNode[]>([]);
    const [loading, setLoading] = useState(false);
    // CLEAN-002-1: Track mounted state to prevent state updates after unmount
    const isMountedRef = useRef(true);

    useEffect(() => {
        isMountedRef.current = true;

        const loadRoot = async () => {
            if (!rootPath) { return; }

            // PERF-005-2: Check cache first before fetching from filesystem
            const cachedNodes = directoryCache.get(rootPath);
            if (cachedNodes) {
                setRootNodes(cachedNodes);
                return;
            }

            setLoading(true);
            try {
                const response = await window.electron.files.listDirectory(rootPath) as unknown as { success?: boolean; data?: Array<{ name: string; isDirectory: boolean }> } | Array<{ name: string; isDirectory: boolean }>;

                // CLEAN-002-1: Check if still mounted after async operation
                if (!isMountedRef.current) {return;}

                // Handle ServiceResponse format: { success, data } or direct array
                const files = ('data' in response && Array.isArray(response.data)) ? response.data : (Array.isArray(response) ? response : []);
                const nodes: FileNode[] = files.map((f: { name: string; isDirectory: boolean }) => ({
                    name: f.name,
                    path: `${rootPath}/${f.name}`.replace(/\/\//g, '/'),
                    isDirectory: f.isDirectory
                })).sort((a: FileNode, b: FileNode) => {
                    if (a.isDirectory === b.isDirectory) { return a.name.localeCompare(b.name); }
                    return a.isDirectory ? -1 : 1;
                });

                // PERF-005-2: Cache the directory listing
                directoryCache.set(rootPath, nodes);

                setRootNodes(nodes);
            } catch (error) {
                // CLEAN-002-1: Only log error if still mounted
                if (isMountedRef.current) {
                    appLogger.error('FileExplorer', 'Failed to load root directory', error as Error);
                }
            } finally {
                // CLEAN-002-1: Only update loading state if still mounted
                if (isMountedRef.current) {
                    setLoading(false);
                }
            }
        };
        void loadRoot();

        // CLEAN-002-1: Cleanup on unmount
        return () => {
            isMountedRef.current = false;
        };
    }, [rootPath]);

    if (loading) { return <div className="p-4 text-xs text-muted-foreground">{t('projectDashboard.loadingFiles')}</div>; }

    return (
        <div className="h-full overflow-y-auto scrollbar-thin scrollbar-thumb-muted">
            {rootNodes.map(node => (
                <FileTreeItem key={node.path} node={node} onSelect={onFileSelect ?? (() => { })} onFolderSelect={onFolderSelect} />
            ))}
            {rootNodes.length === 0 && (
                <div className="p-4 text-xs text-muted-foreground text-center">{t('projectDashboard.emptyDir')}</div>
            )}
        </div>
    );
};

import { WorkspaceTreeItem } from '@renderer/features/projects/components/WorkspaceTreeItem';
import { FileNode } from '@renderer/features/projects/components/WorkspaceTreeItem';
import { ChevronDown, ChevronRight, Folder, Server, X } from 'lucide-react';
import React, { useCallback, useMemo } from 'react';
import { List, RowComponentProps } from 'react-window';

import { cn } from '@/lib/utils';
import { WorkspaceEntry, WorkspaceMount } from '@/types';

// PERF-001-3: Virtualization threshold and constants
const VIRTUALIZATION_THRESHOLD = 50;
const ITEM_HEIGHT = 28; // Height of each tree item in pixels
const MAX_VISIBLE_HEIGHT = 400; // Maximum height for virtualized list

interface WorkspaceMountItemProps {
    mount: WorkspaceMount;
    mountsCount: number;
    mountStatus: Record<string, string>;
    isExpanded: boolean;
    onToggle: (mount: WorkspaceMount) => void;
    onRemove: (id: string) => void;
    onContextMenu: (e: React.MouseEvent, mountId: string) => void;
    rootNodes: FileNode[];
    loading: boolean;
    refreshSignal: number;
    onOpenFile: (entry: WorkspaceEntry) => void;
    onSelectEntry: (entry: WorkspaceEntry) => void;
    selectedEntry?: WorkspaceEntry | null;
    onEnsureMount?: (mount: WorkspaceMount) => Promise<boolean> | boolean;
    onTreeItemContextMenu: (e: React.MouseEvent, entry: WorkspaceEntry) => void;
    t: (key: string) => string;
}

// Status color lookup table to reduce complexity
const STATUS_COLOR_MAP: Record<string, string> = {
    'connected': 'bg-success',
    'connecting': 'bg-warning animate-pulse',
};

interface MountIconProps {
    mountType: WorkspaceMount['type'];
}

const MountIcon: React.FC<MountIconProps> = ({ mountType }) => {
    return mountType === 'ssh'
        ? <Server className="w-3.5 h-3.5 text-indigo" />
        : <Folder className="w-3.5 h-3.5 text-success" />;
};

interface MountStatusIndicatorProps {
    mountId: string;
    mountType: WorkspaceMount['type'];
    status: string;
}

const MountStatusIndicator: React.FC<MountStatusIndicatorProps> = ({ mountType, status }) => {
    if (mountType === 'local') {
        return null;
    }

    const statusColor = STATUS_COLOR_MAP[status] || 'bg-destructive/50';

    return (
        <div
            className={cn('w-1.5 h-1.5 rounded-full', statusColor)}
            title={status}
        />
    );
};

interface MountHeaderProps {
    mount: WorkspaceMount;
