    status: string;
    onToggle: (mount: WorkspaceMount) => void;
    onRemove: (id: string) => void;
    onContextMenu: (e: React.MouseEvent, mountId: string) => void;
    t: (key: string) => string;
}

const MountHeader: React.FC<MountHeaderProps> = ({
    mount,
