// PERF-001-3: Props for virtualized row rendering
interface VirtualizedRowProps {
    nodes: FileNode[];
    mount: WorkspaceMount;
    refreshSignal: number;
    onOpenFile: (entry: WorkspaceEntry) => void;
    onSelectEntry: (entry: WorkspaceEntry) => void;
    selectedEntry?: WorkspaceEntry | null;
    onEnsureMount?: (mount: WorkspaceMount) => Promise<boolean> | boolean;
    onContextMenu: (e: React.MouseEvent, entry: WorkspaceEntry) => void;
    t: (key: string) => string;
}

// PERF-001-3: Virtualized row component for large file lists
const VirtualizedTreeRow: React.FC<RowComponentProps<VirtualizedRowProps>> = ({
    index,
    style,
    nodes,
    mount,
    refreshSignal,
    onOpenFile,
    onSelectEntry,
    selectedEntry,
    onEnsureMount,
    onContextMenu,
    t
}) => {
    const node = nodes[index];
    if (!node) {
        return null;
    }
    return (
        <div style={style}>
            <WorkspaceTreeItem
                node={node}
                mount={mount}
                level={0}
                refreshSignal={refreshSignal}
                onOpenFile={onOpenFile}
                onSelectEntry={onSelectEntry}
                selectedEntry={selectedEntry}
                onEnsureMount={onEnsureMount}
                onContextMenu={onContextMenu}
                t={t}
            />
        </div>
    );
};

export const WorkspaceMountItem: React.FC<WorkspaceMountItemProps> = ({
    mount,
    mountsCount,
    mountStatus,
    isExpanded,
    onToggle,
    onRemove,
    onContextMenu,
    rootNodes,
    loading,
    refreshSignal,
    onOpenFile,
    onSelectEntry,
    selectedEntry,
    onEnsureMount,
    onTreeItemContextMenu,
    t
}) => {
    const showHeader = mountsCount > 1 || mount.type !== 'local';

    // PERF-001-3: Use virtualization for large root node lists
    const shouldVirtualize = rootNodes.length > VIRTUALIZATION_THRESHOLD;

    // PERF-001-3: Memoize row props to prevent re-renders
    const rowProps = useMemo<VirtualizedRowProps>(() => ({
        nodes: rootNodes,
        mount,
        refreshSignal,
        onOpenFile,
        onSelectEntry,
        selectedEntry,
        onEnsureMount,
        onContextMenu: onTreeItemContextMenu,
        t
    }), [rootNodes, mount, refreshSignal, onOpenFile, onSelectEntry, selectedEntry, onEnsureMount, onTreeItemContextMenu, t]);

    // PERF-001-3: Memoized row component that combines base props with rowProps
    const RowComponent = useCallback(
        (props: RowComponentProps<VirtualizedRowProps>) => <VirtualizedTreeRow {...props} />,
        []
    );

    // PERF-001-3: Calculate list height based on item count
    const listHeight = useMemo(() => {
        return Math.min(rootNodes.length * ITEM_HEIGHT, MAX_VISIBLE_HEIGHT);
    }, [rootNodes.length]);

    return (
        <div className="group/mount">
            {showHeader && (
                <MountHeader
                    mount={mount}
                    isExpanded={isExpanded}
                    status={mountStatus[mount.id]}
                    onToggle={onToggle}
                    onRemove={onRemove}
                    onContextMenu={onContextMenu}
                    t={t}
                />
            )}

            <div
                className={cn(
                    showHeader && !isExpanded ? 'hidden' : 'block',
                    showHeader ? 'ml-0' : ''
                )}
            >
                <div className="space-y-0 relative">
                    {/* PERF-001-3: Use virtualized list for large datasets */}
                    {shouldVirtualize ? (
                        <List
                            style={{ height: listHeight }}
                            rowCount={rootNodes.length}
                            rowHeight={ITEM_HEIGHT}
                            rowComponent={RowComponent}
                            rowProps={rowProps}
                            overscanCount={5}
                        />
                    ) : (
                        rootNodes.map((node) => (
                            <WorkspaceTreeItem
                                key={`${mount.id}:${node.path}`}
                                node={node}
                                mount={mount}
                                level={0}
                                refreshSignal={refreshSignal}
                                onOpenFile={onOpenFile}
                                onSelectEntry={onSelectEntry}
                                selectedEntry={selectedEntry}
                                onEnsureMount={onEnsureMount}
                                onContextMenu={onTreeItemContextMenu}
                                t={t}
                            />
                        ))
                    )}
                    {rootNodes.length === 0 && !loading && (
                        <div className="text-xxs text-muted-foreground/40 pl-4 py-2 italic flex items-center gap-2">
                            {t('workspace.emptyFolder')}
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
};

import { useCallback, useEffect, useMemo, useState } from 'react';

import { Project } from '@/types';

import { ModelOption } from '../components/agent/TaskInputForm';
import { TaskHistoryItem } from '../components/agent/TaskSidebar';

// Helper to map agent state to UI status
const mapStateToStatus = (state: string): TaskHistoryItem['status'] => {
    switch (state) {
        case 'completed':
            return 'completed';
        case 'failed':
            return 'failed';
        case 'paused':
            return 'paused';
        case 'waiting_user':
            return 'paused'; // Interrupted looks like paused
        default:
            return 'running';
    }
};

export const useAgentHistory = (project: Project) => {
    const [taskHistory, setTaskHistory] = useState<TaskHistoryItem[]>([]);

    const [selectedModel, setSelectedModel] = useState<ModelOption | null>(null);

    const loadTaskHistory = useCallback(async () => {
        try {
            const result = await window.electron.batch.invoke([{
                channel: 'project-agent:get-task-history',
                args: [{ projectId: project.id }]
            }]);
            const tasks = result.results[0].data as import('@shared/types/project-agent').AgentTaskHistoryItem[];

            if (tasks && Array.isArray(tasks)) {
                const history: TaskHistoryItem[] = tasks.map(task => ({
                    id: task.id,
                    description: task.description,
                    provider: task.provider || 'unknown',
                    model: task.model || 'unknown',
                    status: mapStateToStatus(task.status),
                    createdAt: new Date(task.createdAt),
                    updatedAt: new Date(task.updatedAt),
                    // completedAt is not in AgentTaskHistoryItem yet, need to add or infer
                    completedAt: ['completed', 'failed', 'error'].includes(task.status) ? new Date(task.updatedAt) : undefined,
                    planCount: 0, // Not available in current history item
                    currentPlan: 0, // Not available
                    latestCheckpointId: task.latestCheckpointId
                    // metrics deliberately omitted for now as they are not in history item
                }));
                setTaskHistory(history);
            }
        } catch (error) {
            window.electron.log.error('Failed to load task history', { error: String(error) });
        }
    }, [project.id]);

    const deleteTask = useCallback(async (taskId: string) => {
        // eslint-disable-next-line no-alert
        if (!window.confirm('Are you sure you want to delete this task?')) {
            return false;
        }
        try {
            const batchResult = await window.electron.batch.invoke([{
                channel: 'project-agent:delete-task',
                args: [{ taskId }]
            }]);
            const result = batchResult.results[0].data as { success: boolean; error?: string };
            if (result.success) {
                await loadTaskHistory();
                return true;
            }
            return false;
        } catch (error) {
            window.electron.log.error('Failed to delete task', { error: String(error) });
            return false;
        }
    }, [loadTaskHistory]);

    const groupedTasks = useMemo(() => {
        const grouped: Record<string, TaskHistoryItem[]> = {};
        taskHistory.forEach(task => {
            grouped[task.provider] ??= [];
            grouped[task.provider].push(task);
        });
        return grouped;
    }, [taskHistory]);

    useEffect(() => {
        const initialize = async () => {
            await loadTaskHistory();
        };
        void initialize();
    }, [loadTaskHistory]);

    return {
        selectedModel,
        setSelectedModel,
        loadTaskHistory,
        deleteTask,
        groupedTasks
    };
};

import { useCallback, useEffect, useState } from 'react';

import { Project } from '@/types';

import { ActivityLog } from '../components/agent/ActivityStream';
import { ExecutionPlan } from '../components/agent/ExecutionPlanView';
import { AttachedFile, ModelOption } from '../components/agent/TaskInputForm';
import { ToolExecution } from '../components/agent/ToolTracking';

import {
    approvePlanHandler,
    fetchTaskDetailsHandler,
    pauseTaskHandler,
    rejectPlanHandler,
    resumeCheckpointHandler,
    resumeTaskHandler,
    saveSnapshotHandler,
    stopTaskHandler
} from './converters/asyncHandlers';
import { invokeStartTask, prepareTaskFiles, validateTaskInput } from './converters/startTaskHandler';
import {
    combineAndSortLogs,
    processEventResponse,
    processMessageResponse,
    processStatusResponse,
    processTelemetryResponse
} from './converters/taskDetailsProcessor';

export interface AgentTaskStatus {
    taskId: string | null;
    state: string;
    progress: number;
    currentStep?: string;
    error?: string | null;
    metrics?: {
        tokensUsed?: number;
        llmCalls?: number;
        toolCalls?: number;
        estimatedCost?: number;
    };
}

/**
 * Hook for managing agent task execution and state
 *
 * @param {Project} project The active project
 * @returns {object} The agent task state and handlers
 */
export const useAgentTask = (project: Project) => {
    const [status, setStatus] = useState<AgentTaskStatus>({
        taskId: null,
        state: 'idle',
        progress: 0,
        currentStep: '',
        error: null
    });
    const [isLoading, setIsLoading] = useState(false);
    const [selectedTaskId, setSelectedTaskId] = useState<string | null>(null);
    const [activityLogs, setActivityLogs] = useState<ActivityLog[]>([]);
    const [toolExecutions, setToolExecutions] = useState<ToolExecution[]>([]);
    const [currentPlan, setCurrentPlan] = useState<ExecutionPlan | null>(null);

    const startTask = useCallback(async (userPrompt: string, attachedFiles: AttachedFile[], selectedModel: ModelOption | null) => {
        // Validate input
        const validationError = validateTaskInput(userPrompt, selectedModel);
        if (validationError) {
            return null;
        }

        setIsLoading(true);
        try {
            // Prepare files
            const agentFiles = prepareTaskFiles(attachedFiles);

            // Clear previous state
            setStatus(prev => ({ ...prev, state: 'initializing' }));
            setActivityLogs([]);
            setToolExecutions([]);
            setCurrentPlan(null);

            // Invoke the start task command (selectedModel is validated above)
            const result = await invokeStartTask(userPrompt, agentFiles, selectedModel as ModelOption, project);

            if (result.success) {
                const taskId = result.taskId ?? null;
                setStatus(prev => ({ ...prev, taskId, state: 'initializing', error: null, progress: 0 }));
                setSelectedTaskId(taskId);
                return taskId;
            } else {
                setStatus(prev => ({ ...prev, error: result.error ?? 'Failed to start task' }));
                return null;
            }
        } catch (error) {
            window.electron.log.error('Failed to start task:', error as Error);
            setStatus(prev => ({ ...prev, error: 'Failed to start task' }));
            return null;
        } finally {
            setIsLoading(false);
        }
    }, [project]);

    const pauseTask = useCallback(async (taskId: string) => {
        try {
            await pauseTaskHandler(taskId);
            setStatus(prev => ({ ...prev, state: 'paused' }));
        } catch (error) {
            window.electron.log.error('Failed to pause task:', error as Error);
        }
    }, []);

    const stopTask = useCallback(async (taskId: string) => {
        try {
            await stopTaskHandler(taskId);
            // Don't clear selectedTaskId - keep task selected to show stopped state
            // The UI will update via events when task is stopped
            setStatus(prev => ({ ...prev, state: 'stopped', error: 'Task stopped by user' }));
        } catch (error) {
            window.electron.log.error('Failed to stop task:', error as Error);
        }
    }, []);

    const saveSnapshot = useCallback(async (taskId: string) => {
        try {
            return await saveSnapshotHandler(taskId);
        } catch (error) {
            window.electron.log.error('Failed to save snapshot:', error as Error);
            return false;
        }
    }, []);

    const loadTaskDetails = useCallback(async (taskId: string) => {
        setIsLoading(true);
        try {
            // Fetch all task details in parallel
            const { statusRes, messagesRes, eventsRes, telemetryRes } = await fetchTaskDetailsHandler(taskId);

            // Process status and get execution plan
            const statusData = processStatusResponse(statusRes);
            setStatus({
                taskId: statusData.taskId,
                state: statusData.state,
                progress: statusData.progress,
                currentStep: statusData.currentStep,
                error: statusData.error,
                metrics: statusData.metrics
            });

            if (statusData.currentPlan) {
                setCurrentPlan(statusData.currentPlan);
            }

            // Process events and messages into activity logs
            const eventLogs = processEventResponse(eventsRes);
            const messageLogs = processMessageResponse(messagesRes);
            const allLogs = combineAndSortLogs(eventLogs, messageLogs);
            setActivityLogs(allLogs);

            // Process telemetry into tool executions
            const executions = processTelemetryResponse(telemetryRes);
            setToolExecutions(executions);
        } catch (error) {
            window.electron.log.error('Failed to load task details:', error as Error);
        } finally {
            setIsLoading(false);
        }
    }, []);

    useEffect(() => {
        if (selectedTaskId) {
            void loadTaskDetails(selectedTaskId);
        }
    }, [selectedTaskId, loadTaskDetails]);

    const resumeTask = useCallback(async (taskId: string) => {
        setIsLoading(true);
        // Immediately update status to show we're resuming
        setStatus(prev => ({ ...prev, state: 'initializing', error: null }));
        try {
            const result = await resumeTaskHandler(taskId);
            if (result.success) {
                setSelectedTaskId(taskId);
                // Don't call loadTaskDetails - the event system will update the UI
                return true;
            }
            // If failed, revert to previous state
            setStatus(prev => ({ ...prev, state: 'failed', error: result.error ?? 'Failed to resume' }));
            return false;
        } catch (error) {
            window.electron.log.error('Failed to resume task:', error as Error);
            setStatus(prev => ({ ...prev, state: 'failed', error: 'Failed to resume task' }));
            return false;
        } finally {
            setIsLoading(false);
        }
    }, []);

    const approvePlan = useCallback(async (taskId: string) => {
        return await approvePlanHandler(taskId);
    }, []);

    const rejectPlan = useCallback(async (taskId: string, reason?: string) => {
        return await rejectPlanHandler(taskId, reason);
    }, []);

    const resumeFromCheckpoint = useCallback(async (checkpointId: string) => {
        setIsLoading(true);
        setStatus(prev => ({ ...prev, state: 'initializing', error: null }));
        try {
            const result = await resumeCheckpointHandler(checkpointId);
            if (result.success) {
                // TaskId will be updated by events, but we can't set it easily here without the task ID
                // The backend resumeFromCheckpoint sets the task as active, so we should receive events.
                return true;
            }
            setStatus(prev => ({ ...prev, state: 'failed', error: result.error ?? 'Failed to resume checkpoint' }));
            return false;
        } catch (error) {
            window.electron.log.error('Failed to resume checkpoint:', error as Error);
            setStatus(prev => ({ ...prev, state: 'failed', error: 'Failed to resume checkpoint' }));
            return false;
        } finally {
            setIsLoading(false);
        }
    }, []);

    return {
        status,
        setStatus,
        isLoading,
        setIsLoading,
        selectedTaskId,
        setSelectedTaskId,
        activityLogs,
        setActivityLogs,
        toolExecutions,
        setToolExecutions,
        currentPlan,
        setCurrentPlan,
        startTask,
        pauseTask,
        stopTask,
        saveSnapshot,
        resumeTask,
        approvePlan,
        rejectPlan,
        resumeFromCheckpoint,
        loadTaskDetails
    };
};

