import { CheckCircle2, Edit2, Power, Server, Shield, Trash2 } from 'lucide-react';
import { useCallback, useEffect, useState } from 'react';

import { useTranslation } from '@/i18n';
import { cn } from '@/lib/utils';

interface MCPServer {
    id: string
    name: string
    command: string
    args: string[]
    description?: string
    env?: Record<string, string>
    enabled?: boolean
    tools?: { name: string; description: string }[]
    category?: string
    publisher?: string
    version?: string
    isOfficial?: boolean
}

export const MCPServersTab = () => {
    const { t } = useTranslation();
    const [servers, setServers] = useState<MCPServer[]>([]);
    const [loading, setLoading] = useState(true);

    const loadServers = useCallback(async () => {
        try {
            setLoading(true);
            const result = await window.electron.mcpMarketplace.installed();
            if (result.success && result.servers) {
                // Properly cast from IpcValue[] to MCPServer[]
                const servers = result.servers as unknown as MCPServer[];
                setServers(servers);
            }
        } catch (error) {
            console.error('Failed to load servers:', error);
        } finally {
            setLoading(false);
        }
    }, []);

    useEffect(() => {
        void loadServers();
    }, [loadServers]);

    const handleToggle = useCallback(
        async (serverId: string, currentEnabled: boolean, isInternal: boolean) => {
            // Internal tools cannot be toggled
            if (isInternal) {
                return;
            }

            try {
                const result = await window.electron.mcpMarketplace.toggle(serverId, !currentEnabled);
                if (result.success) {
                    await loadServers();
                }
            } catch (error) {
                console.error('Failed to toggle server:', error);
            }
        },
        [loadServers]
    );

    const handleDelete = useCallback(
        async (serverId: string, isInternal: boolean) => {
            // Internal tools cannot be deleted
            if (isInternal) {
                return;
            }

            try {
                const result = await window.electron.mcpMarketplace.uninstall(serverId);
                if (result.success) {
                    await loadServers();
                }
            } catch (error) {
                console.error('Failed to delete server:', error);
            }
        },
        [loadServers]
    );

    return (
        <div className="h-full flex flex-col p-6 space-y-6">
            <div className="flex items-center justify-between">
                <div>
                    <h2 className="text-lg font-semibold flex items-center gap-2">
                        <Server className="w-5 h-5" />
                        {t('settings.mcp.servers.title')}
                    </h2>
                    <p className="text-sm text-muted-foreground">{t('settings.mcp.servers.subtitle')}</p>
                </div>
                <div className="text-xs text-muted-foreground">
                    {servers.filter(s => s.enabled).length} / {servers.length} {t('settings.mcp.servers.enabled')}
                </div>
            </div>

            {loading ? (
                <div className="flex items-center justify-center py-12">
                    <p className="text-sm text-muted-foreground">{t('common.loading')}</p>
                </div>
            ) : (
                <div className="grid gap-3">
                    {servers.map(server => {
                        const isInternal = server.category === 'Internal';
                        return (
                            <div
                                key={server.id}
                                className={cn(
                                    'group flex items-center justify-between p-4 border rounded-xl transition-all',
                                    server.enabled
                                        ? 'bg-primary/5 border-primary/30'
                                        : 'bg-muted/30 border-border/50 hover:border-border/80'
                                )}
                            >
                                <div className="flex items-center gap-4 flex-1">
                                    <div
                                        className={cn(
                                            'p-2.5 rounded-lg',
                                            server.enabled
                                                ? 'bg-success/10 text-success'
                                                : 'bg-muted/10 text-muted-foreground'
                                        )}
                                    >
                                        <Server className="w-5 h-5" />
                                    </div>
                                    <div className="flex-1">
                                        <div className="flex items-center gap-2">
                                            <h3 className="font-medium">{server.name}</h3>
                                            {server.isOfficial && (
                                                <Shield className="w-3.5 h-3.5 text-primary" />
                                            )}
                                            {server.category && (
                                                <span className={cn(
                                                    "px-1.5 py-0.5 rounded text-xxs uppercase border",
                                                    isInternal
                                                        ? "bg-primary/10 text-primary border-primary/30"
                                                        : "bg-muted text-muted-foreground"
                                                )}>
                                                    {server.category}
                                                </span>
                                            )}
                                            {server.version && (
                                                <span className="text-xxs text-muted-foreground">
                                                    v{server.version}
                                                </span>
                                            )}
                                        </div>
                                        <p className="text-xs text-muted-foreground mt-0.5">
                                            {server.description || `${server.command} ${server.args.join(' ')}`}
                                        </p>
                                        {server.publisher && (
                                            <p className="text-xxs text-muted-foreground/60 mt-1">
                                                {t('mcp.byAuthor', { author: server.publisher, version: '' })}
                                            </p>
                                        )}
                                        {server.tools && server.tools.length > 0 && (
                                            <p className="text-xxs text-muted-foreground/60 mt-1">
                                                {server.tools.length} {server.tools.length === 1 ? 'tool' : 'tools'}
                                            </p>
                                        )}
                                    </div>
                                </div>

                                <div className="flex items-center gap-3">
                                    {/* Enable/Disable Toggle */}
                                    <button
                                        onClick={() => handleToggle(server.id, server.enabled || false, isInternal)}
                                        disabled={isInternal}
                                        className={cn(
                                            'flex items-center gap-2 px-3 py-1.5 rounded-full border text-xs font-medium transition-all',
                                            isInternal
                                                ? 'bg-primary/5 border-primary/30 text-primary cursor-default'
                                                : server.enabled
                                                    ? 'bg-success/10 border-success/30 text-success hover:bg-success/20'
                                                    : 'bg-muted/50 border-border/50 text-muted-foreground hover:bg-muted'
                                        )}
                                        title={isInternal ? t('settings.mcp.servers.internalAlwaysEnabled') : ''}
                                    >
                                        <Power className={cn('w-3.5 h-3.5', server.enabled && 'fill-current')} />
                                        {server.enabled ? t('settings.mcp.status.enabled') : t('settings.mcp.status.disabled')}
                                    </button>

                                    {/* Status Indicator */}
                                    <div className="flex items-center gap-2 px-3 py-1 bg-background rounded-full border border-border/50">
                                        {server.enabled ? (
                                            <CheckCircle2 className="w-3.5 h-3.5 text-success" />
                                        ) : (
                                            <div className="w-2 h-2 rounded-full bg-muted" />
                                        )}
                                        <span className="text-xs capitalize">
                                            {server.enabled ? t('settings.mcp.status.active') : t('settings.mcp.status.inactive')}
                                        </span>
                                    </div>

                                    {/* Action Buttons (hidden for internal tools) */}
                                    {!isInternal && (
                                        <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                            <button
                                                className="p-2 hover:bg-muted text-muted-foreground hover:text-foreground rounded-lg transition-colors"
                                                title={t('common.edit')}
                                            >
                                                <Edit2 className="w-4 h-4" />
                                            </button>
                                            <button
                                                onClick={() => handleDelete(server.id, isInternal)}
                                                className="p-2 hover:bg-destructive/10 text-muted-foreground hover:text-destructive rounded-lg transition-colors"
                                                title={t('common.delete')}
                                            >
                                                <Trash2 className="w-4 h-4" />
                                            </button>
                                        </div>
                                    )}
                                </div>
                            </div>
                        );
                    })}

                    {servers.length === 0 && (
                        <div className="flex flex-col items-center justify-center py-12 text-muted-foreground/50 border border-dashed border-border/50 rounded-xl">
                            <Server className="w-10 h-10 mb-3 opacity-20" />
                            <p className="mb-1">{t('settings.mcp.servers.empty')}</p>
                            <p className="text-xs">{t('settings.mcp.servers.emptyHint')}</p>
                        </div>
                    )}
                </div>
            )}

            {/* Info Box */}
            {servers.length > 0 && (
                <div className="p-4 bg-muted/30 border border-border/30 rounded-lg">
                    <p className="text-xs text-muted-foreground">
                        <strong>{t('settings.mcp.servers.note')}:</strong> {t('settings.mcp.servers.noteText')}
                    </p>
                </div>
            )}
        </div>
    );
};

import { useCallback, useState } from 'react';

import { AppSettings } from '@/types';

import { DeviceCodeModalState } from '../components/DeviceCodeModal';

const INITIAL_MODAL_STATE: DeviceCodeModalState = {
    isOpen: false,
    userCode: '',
    verificationUri: '',
    provider: 'github',
    status: 'pending',
    errorMessage: undefined
};

export function useDeviceAuth(
    settings: AppSettings | null,
    updateSettings: (s: AppSettings, save: boolean) => Promise<void>,
    setAuthBusy: (busy: string | null) => void,
    setAuthNotice: (msg: string, duration?: number) => void,
    onRefreshModels?: (bypassCache?: boolean) => void
) {
    const [deviceCodeModal, setDeviceCodeModal] = useState<DeviceCodeModalState>(INITIAL_MODAL_STATE);

    const connectGitHubProfile = useCallback(async () => {
        if (!settings) { return; }
        setAuthBusy('github');
        setAuthNotice('');
        try {
            const data = await window.electron.githubLogin('profile');

            // Open the modal with device code
            if (data.user_code && data.verification_uri) {
                setDeviceCodeModal({
                    isOpen: true,
                    userCode: data.user_code,
                    verificationUri: data.verification_uri,
                    provider: 'github',
                    status: 'pending',
                    errorMessage: undefined
                });
                window.electron.openExternal(data.verification_uri);
            }

            const pollResult = await window.electron.pollToken(data.device_code, data.interval, 'profile');
            if (pollResult.success && pollResult.token) {
                const updated: AppSettings = {
                    ...settings,
                    github: { username: (settings.github as { username?: string }).username ?? 'GitHub User', token: pollResult.token }
                };
                await updateSettings(updated, true);
                onRefreshModels?.(true);
                setDeviceCodeModal(prev => ({ ...prev, status: 'success' }));
                setTimeout(() => setDeviceCodeModal(INITIAL_MODAL_STATE), 2000);
            } else {
                setDeviceCodeModal(prev => ({ ...prev, status: 'error', errorMessage: 'GitHub bağlanamadı.' }));
            }
        } catch (error) {
            console.error('GitHub auth failed:', error);
            setDeviceCodeModal(prev => ({ ...prev, status: 'error', errorMessage: 'GitHub bağlanamadı.' }));
        } finally {
            setAuthBusy(null);
        }
    }, [settings, updateSettings, setAuthBusy, setAuthNotice]);

    const connectCopilot = useCallback(async () => {
        if (!settings) { return; }
        setAuthBusy('copilot');
        setAuthNotice('');
        try {
            const data = await window.electron.githubLogin('copilot');

            // Open the modal with device code
            if (data.user_code && data.verification_uri) {
                setDeviceCodeModal({
                    isOpen: true,
                    userCode: data.user_code,
                    verificationUri: data.verification_uri,
                    provider: 'copilot',
                    status: 'pending',
                    errorMessage: undefined
                });
                window.electron.openExternal(data.verification_uri);
            }

            const pollResult = await window.electron.pollToken(data.device_code, data.interval, 'copilot');
            if (pollResult.success && pollResult.token) {
                const updated: AppSettings = {
                    ...settings,
                    copilot: { ...(settings.copilot ?? { connected: false }), connected: true, token: pollResult.token }
                };
                await updateSettings(updated, true);
                onRefreshModels?.(true);
                setDeviceCodeModal(prev => ({ ...prev, status: 'success' }));
                setTimeout(() => setDeviceCodeModal(INITIAL_MODAL_STATE), 2000);
            } else {
                setDeviceCodeModal(prev => ({ ...prev, status: 'error', errorMessage: 'Copilot bağlanamadı.' }));
            }
        } catch (error) {
            console.error('Copilot auth failed:', error);
            setDeviceCodeModal(prev => ({ ...prev, status: 'error', errorMessage: 'Copilot bağlanamadı.' }));
        } finally {
            setAuthBusy(null);
        }
    }, [settings, updateSettings, setAuthBusy, setAuthNotice, onRefreshModels]);

    const closeDeviceCodeModal = useCallback(() => {
        setDeviceCodeModal(INITIAL_MODAL_STATE);
    }, []);

    return {
        deviceCodeModal,
        connectGitHubProfile,
        connectCopilot,
        closeDeviceCodeModal
    };
}

import { useTranslation } from '@renderer/i18n';
import { ChevronDown, Maximize2, Minimize2, Plus, Terminal, TerminalSquare, X } from 'lucide-react';
import { memo, useCallback, useEffect, useRef, useState } from 'react';
import { Terminal as XTerm } from 'xterm';
import { FitAddon } from 'xterm-addon-fit';

import { useTheme } from '@/hooks/useTheme';
import { AnimatePresence, motion } from '@/lib/framer-motion-compat';
import { getTerminalTheme } from '@/lib/terminal-theme';
import { cn } from '@/lib/utils';
import { TerminalTab } from '@/types';
import { appLogger } from '@/utils/renderer-logger';

import 'xterm/css/xterm.css';

const initializedTerminals = new Set<string>();
const initializingTerminals = new Set<string>();

interface TerminalPanelProps { isOpen: boolean; onToggle: () => void; height: number; onHeightChange: (height: number) => void; projectPath?: string; tabs: TerminalTab[]; activeTabId: string | null; setTabs: (tabs: TerminalTab[] | ((prev: TerminalTab[]) => TerminalTab[])) => void; setActiveTabId: (id: string | null) => void; }

const useTerminalSession = (tab: TerminalTab, containerRef: React.RefObject<HTMLDivElement>, projectPath: string | undefined) => {
    const xtermRef = useRef<XTerm | null>(null);
    const fitAddonRef = useRef<FitAddon | null>(null);
    const [isReady, setIsReady] = useState(false);
    const [hasError, setHasError] = useState(false);
    const isInitializedRef = useRef(false);
    // CLEAN-002-2: Track mounted state to prevent state updates after unmount
    const isMountedRef = useRef(true);

    useEffect(() => {
        isMountedRef.current = true;

        if (initializedTerminals.has(tab.id) || initializingTerminals.has(tab.id) || !containerRef.current || isInitializedRef.current) {
            return;
        }
        isInitializedRef.current = true;
        initializingTerminals.add(tab.id);

        const term = new XTerm({ cursorBlink: true, fontSize: 13, fontFamily: "'JetBrains Mono', 'Cascadia Code', Consolas, monospace", theme: getTerminalTheme(), allowProposedApi: true, scrollback: 10000, cols: 80, rows: 24 });
        const fitAddon = new FitAddon();
        term.loadAddon(fitAddon);
        term.open(containerRef.current);
        xtermRef.current = term;
        fitAddonRef.current = fitAddon;

        let sessionCreated = false;
        const setupEvents = (id: string) => {
            term.onResize(s => {
                if (sessionCreated && isMountedRef.current) {
                    void window.electron.terminal.resize(id, s.cols, s.rows);
                }
            });
            term.onData(d => {
                if (sessionCreated && isMountedRef.current) {
                    void window.electron.terminal.write(id, d);
                }
            });
        };

        const createBackendSession = async (cols: number, rows: number) => {
            // CLEAN-002-2: Check if still mounted before async operations
            if (!isMountedRef.current) {return null;}
            if (!(await window.electron.terminal.isAvailable())) {
                if (isMountedRef.current) {
                    term.write('\r\n\x1b[31m[ERROR] Terminal service not available.\x1b[0m\r\n');
                }
                return null;
            }
            if (!isMountedRef.current) {return null;}
            const result = await window.electron.terminal.create({ id: tab.id, shell: tab.type, ...(projectPath ? { cwd: projectPath } : {}), cols, rows });
            if (!result.success && isMountedRef.current) {
                term.write(`\r\n\x1b[31m[ERROR] ${result.error}\x1b[0m\r\n`);
                return null;
            }
            return result;
        };

        const initSession = async () => {
            if (initializedTerminals.has(tab.id)) {
                initializingTerminals.delete(tab.id);
                return;
            }
            await new Promise(r => { setTimeout(r, 50); });
            // CLEAN-002-2: Check if still mounted after delay
            if (!isMountedRef.current) {
                initializingTerminals.delete(tab.id);
                return;
            }
            try {
                if (containerRef.current?.offsetParent) {
                    fitAddon.fit();
                }
            } catch { /* ignore */ }
            const res = await createBackendSession(term.cols || 80, term.rows || 24);
            // CLEAN-002-2: Check if still mounted after async operation
            if (!isMountedRef.current) {
                initializingTerminals.delete(tab.id);
                return;
            }
            if (!res) {
                setHasError(true);
                initializingTerminals.delete(tab.id);
                return;
            }
            sessionCreated = true;
            initializedTerminals.add(tab.id);
            initializingTerminals.delete(tab.id);
            setupEvents(tab.id);
            try {
                const b = await window.electron.terminal.readBuffer(tab.id);
                // CLEAN-002-2: Check if still mounted before writing
                if (b && isMountedRef.current) {
                    term.write(b);
                }
            } catch { /* ignore */ }
            // CLEAN-002-2: Only update state if still mounted
            if (isMountedRef.current) {
                setIsReady(true);
            }
        };

        void initSession();

        return () => {
            // CLEAN-002-2: Mark as unmounted first
            isMountedRef.current = false;
            isInitializedRef.current = false;

            // CLEAN-002-2: Clean up terminal references
            xtermRef.current = null;
            fitAddonRef.current = null;

            if (sessionCreated) {
                initializedTerminals.delete(tab.id);
                void window.electron.terminal.kill(tab.id);
            }
            initializingTerminals.delete(tab.id);
            try {
                term.dispose();
            } catch { /* ignore */ }
        };
    }, [tab.id, tab.type, projectPath, containerRef]);

    return { xtermRef, fitAddonRef, isReady, hasError };
};

const TerminalSession = memo(({ tab, isActive, onClose, projectPath }: { tab: TerminalTab, isActive: boolean, onClose: () => void, projectPath?: string }) => {
    const { t } = useTranslation();
    const containerRef = useRef<HTMLDivElement>(null);
    const { theme } = useTheme();
    const { xtermRef, fitAddonRef, isReady, hasError } = useTerminalSession(tab, containerRef, projectPath);

    useEffect(() => {
        if (xtermRef.current) {
            xtermRef.current.options.theme = getTerminalTheme();
        }
    }, [theme, xtermRef]);

    const safeFit = useCallback(() => {
        if (!fitAddonRef.current || !containerRef.current || !isActive) {
            return;
        }
        try {
            if (containerRef.current.offsetParent) {
                fitAddonRef.current.fit();
            }
        } catch { /* ignore */ }
    }, [isActive, fitAddonRef]);

    useEffect(() => {
        if (!isReady || !xtermRef.current) {
            return;
        }
        const hData = (e: Event) => {
            const d = (e as CustomEvent).detail;
            if (d?.id === tab.id && xtermRef.current) {
                xtermRef.current.write(d.data);
            }
        };
        const hExit = (e: Event) => {
            const d = (e as CustomEvent).detail;
            if (d?.id === tab.id) {
                if (xtermRef.current) {
                    xtermRef.current.write(`\r\n\x1b[33m[Terminal exited with code ${d.code ?? 0}]\x1b[0m\r\n`);
                }
                onClose();
            }
        };
        window.addEventListener('terminal-data-multiplex', hData);
        window.addEventListener('terminal-exit-multiplex', hExit);
        return () => {
            window.removeEventListener('terminal-data-multiplex', hData);
            window.removeEventListener('terminal-exit-multiplex', hExit);
        };
    }, [tab.id, isReady, onClose, xtermRef]);

    useEffect(() => {
        if (!isActive) {
            return;
        }
        const timer = setTimeout(safeFit, 100);
        return () => {
            clearTimeout(timer);
        };
    }, [isActive, safeFit]);

    useEffect(() => {
        if (!containerRef.current) {
            return;
        }
        const observer = new ResizeObserver(() => {
            if (isActive) {
                safeFit();
            }
        });
        observer.observe(containerRef.current);
        return () => { observer.disconnect(); };
    }, [isActive, safeFit]);

    return (
        <div className={cn("h-full w-full bg-background", isActive ? "block" : "hidden")} style={{ paddingLeft: '8px' }}>
            {hasError && <div className="absolute inset-0 flex items-center justify-center bg-background/80 z-10"><div className="text-center px-4"><p className="text-destructive text-sm mb-1">{t('terminal.sessionFailed')}</p><p className="text-muted-foreground text-xs">{t('terminal.closeAndCreate')}</p></div></div>}
            <div ref={containerRef} className="h-full w-full" />
        </div>
    );
});
TerminalSession.displayName = 'TerminalSession';

export function TerminalPanel({ isOpen, onToggle, height, onHeightChange, projectPath, tabs, activeTabId, setTabs, setActiveTabId }: TerminalPanelProps) {
    const { t } = useTranslation();
    const [isResizing, setIsResizing] = useState(false);
    const [isMaximized, setIsMaximized] = useState(false);
    const [showNewTerminalMenu, setShowNewTerminalMenu] = useState(false);
    const [availableShells, setAvailableShells] = useState<{ id: string, name: string, path: string }[]>([]);

    const createTerminal = useCallback((type: string) => {
        const id = Math.random().toString(36).substring(2, 9);
        const name = `${availableShells.find(s => s.id === type)?.name ?? type} ${tabs.filter(t => t.type === type).length + 1}`;
        setTabs(prev => [...prev, { id, name, type, cwd: projectPath ?? '', isRunning: true, status: 'idle', history: [], command: '' }]);
        setActiveTabId(id);
        setShowNewTerminalMenu(false);
    }, [availableShells, projectPath, setTabs, setActiveTabId, tabs]);

    const isCreatingRef = useRef(false);
    const hasAutoCreatedRef = useRef(false);

    useEffect(() => {
        if (!isOpen) {
            hasAutoCreatedRef.current = false;
            isCreatingRef.current = false;
        }
    }, [isOpen]);

    useEffect(() => {
        const loadShells = async () => {
            if (isCreatingRef.current || hasAutoCreatedRef.current || tabs.length > 0) {
                return;
            }
            try {
                if (!(await window.electron.terminal.isAvailable())) {
                    return;
                }
                const shells = await window.electron.terminal.getShells();
                setAvailableShells(shells);
                if (isOpen && tabs.length === 0 && shells.length > 0) {
                    isCreatingRef.current = true;
                    hasAutoCreatedRef.current = true;
                    setTimeout(() => {
                        if (tabs.length === 0 && shells[0]) {
                            createTerminal(shells[0].id);
                        }
                        isCreatingRef.current = false;
                    }, 100);
                }
            } catch (error) {
                appLogger.error('TerminalPanel', 'Failed to load shells', error as Error);
                isCreatingRef.current = false;
                hasAutoCreatedRef.current = false;
            }
        };
        if (isOpen) {
            void loadShells();
        }
    }, [isOpen, tabs.length, createTerminal]);

    const closeTab = useCallback((id: string) => {
        initializedTerminals.delete(id);
        initializingTerminals.delete(id);
        void window.electron.terminal.kill(id);
        setTabs(prev => {
            const next = prev.filter(t => t.id !== id);
            if (activeTabId === id) {
                setActiveTabId(next[next.length - 1]?.id ?? null);
            }
            return next;
        });
    }, [activeTabId, setTabs, setActiveTabId]);

    useEffect(() => {
        const c1 = window.electron.terminal.onData(p => { window.dispatchEvent(new CustomEvent('terminal-data-multiplex', { detail: p })); });
        const c2 = window.electron.terminal.onExit(p => { window.dispatchEvent(new CustomEvent('terminal-exit-multiplex', { detail: p })); });
        return () => {
            c1();
            c2();
        };
    }, []);

    useEffect(() => {
        if (!isResizing) {
            return;
        }
        const hMove = (e: MouseEvent) => {
            onHeightChange(Math.min(Math.max(150, window.innerHeight - e.clientY), window.innerHeight * 0.8));
        };
        const hUp = () => {
            setIsResizing(false);
        };
        document.addEventListener('mousemove', hMove);
        document.addEventListener('mouseup', hUp);
        return () => {
            document.removeEventListener('mousemove', hMove);
            document.removeEventListener('mouseup', hUp);
        };
    }, [isResizing, onHeightChange]);

    return (
        <motion.div initial={{ y: 20, opacity: 0 }} animate={{ y: 0, opacity: 1 }} style={{ height: isMaximized ? '70vh' : height }} className="flex flex-col bg-background border-t border-border overflow-hidden shadow-2xl h-full">
            <div onMouseDown={(e) => { e.preventDefault(); setIsResizing(true); }} className={cn("h-1 cursor-ns-resize bg-transparent hover:bg-primary/50 transition-colors w-full relative z-10", isResizing && "bg-primary")} />
            <div className="flex items-center justify-between px-2 py-1.5 bg-card/40 border-b border-border backdrop-blur-sm">
                <div className="flex items-center gap-1 overflow-x-auto custom-scrollbar no-thumb">
                    {tabs.map(tab => (
                        <button key={tab.id} onClick={() => setActiveTabId(tab.id)} className={cn("flex items-center gap-2 px-3 py-1.5 rounded-md text-xs font-medium transition-all whitespace-nowrap border border-transparent", activeTabId === tab.id ? "bg-accent text-foreground border-border shadow-sm" : "text-muted-foreground hover:text-foreground hover:bg-accent/50")}>
                            <TerminalSquare className={cn("w-3.5 h-3.5", activeTabId === tab.id ? "text-primary" : "opacity-70")} />
                            {tab.name}
                            <div onClick={(e) => { e.stopPropagation(); closeTab(tab.id); }} className="ml-1 p-0.5 rounded hover:bg-destructive/10 text-muted-foreground hover:text-destructive transition-colors"><X className="w-3 h-3" /></div>
                        </button>
                    ))}
                    <div className="relative ml-1">
                        <button onClick={() => { setShowNewTerminalMenu(!showNewTerminalMenu); }} className="p-1.5 rounded-md text-muted-foreground hover:text-foreground hover:bg-accent/50 transition-colors"><Plus className="w-3.5 h-3.5" /></button>
                        <AnimatePresence>
                            {showNewTerminalMenu && (
                                <motion.div initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }} exit={{ opacity: 0, scale: 0.95 }} className="absolute bottom-full left-0 mb-2 py-1 bg-popover border border-border rounded-lg shadow-xl z-50 min-w-[140px] overflow-hidden">
                                    {availableShells.length > 0 ? availableShells.map(s => <button key={s.id} onClick={() => { createTerminal(s.id); }} className="w-full px-3 py-2 text-left text-xs font-medium hover:bg-accent/50 transition-colors flex items-center gap-2 text-foreground"><span className="opacity-50">&gt;_</span>{s.name}</button>) : <div className="px-3 py-2 text-xs text-muted-foreground">{t('terminal.noShellsFound')}</div>}
                                </motion.div>
                            )}
                        </AnimatePresence>
                    </div>
                </div>
                <div className="flex items-center gap-1">
                    <button onClick={() => { setIsMaximized(!isMaximized); }} className="p-1.5 text-muted-foreground hover:text-foreground transition-colors">{isMaximized ? <Minimize2 className="w-3.5 h-3.5" /> : <Maximize2 className="w-3.5 h-3.5" />}</button>
                    <button onClick={onToggle} className="p-1.5 text-muted-foreground hover:text-foreground transition-colors"><ChevronDown className="w-3.5 h-3.5" /></button>
                </div>
            </div>
            <div className="flex-1 overflow-hidden relative bg-background">
                {tabs.map(tab => <TerminalSession key={tab.id} tab={tab} isActive={activeTabId === tab.id} onClose={() => { closeTab(tab.id); }} projectPath={projectPath} />)}
                {tabs.length === 0 && (
                    <div className="absolute inset-0 flex flex-col items-center justify-center text-muted-foreground opacity-50">
                        <Terminal className="w-12 h-12 mb-4 opacity-20" />
                        <p className="text-sm">{t('terminal.noActiveSessions')}</p>
                        <button onClick={() => { createTerminal(availableShells[0]?.id || 'powershell'); }} className="mt-4 px-4 py-2 bg-primary/20 hover:bg-primary/30 text-primary rounded-lg text-xs font-bold transition-all border border-primary/30">{t('terminal.startNewSession')}</button>
                    </div>
                )}
            </div>
        </motion.div>
    );
}

import { useTextToSpeech } from '@renderer/features/chat/hooks/useTextToSpeech';
import { Language, useLanguage } from '@renderer/i18n';
import { useEffect, useState } from 'react';

export function useAppInitialization() {
    const { language, setLanguage } = useLanguage();
    const { speak: handleSpeak } = useTextToSpeech();
    const [showExtensionWarning, setShowExtensionWarning] = useState(false);

    useEffect(() => { window.TandemSpeak = handleSpeak; }, [handleSpeak]);

    useEffect(() => {
        document.documentElement.dir = language === 'ar' ? 'rtl' : 'ltr';
        document.documentElement.lang = language;
    }, [language]);

    useEffect(() => {
        const abortController = new AbortController();
        
        const detectLanguage = async () => {
            if (abortController.signal.aborted) { return; }
            
            const settings = await window.electron.getSettings();
            if (!abortController.signal.aborted && !settings?.general?.language) {
                const browserLang = window.navigator.language.split('-')[0];
                const supported = ['tr', 'en', 'de', 'fr', 'es', 'ja', 'zh', 'ar'];
                if (supported.includes(browserLang)) {
                    void setLanguage(browserLang as Language);
                }
            }
        };
        void detectLanguage();
        
        return () => {
            abortController.abort();
        };
    }, [setLanguage]);

    useEffect(() => {
        const abortController = new AbortController();
        
        const checkExtensionWarning = async () => {
            if (abortController.signal.aborted) { return; }
            
            try {
                const shouldShow = await window.electron.extension.shouldShowWarning();
                if (!abortController.signal.aborted) {
                    setShowExtensionWarning(shouldShow);
                }
            } catch (error) {
                console.error('[Extension] Failed to check warning status:', error);
            }
        };
        void checkExtensionWarning();
        
        return () => {
            abortController.abort();
        };
    }, []);

    return {
        showExtensionWarning,
        setShowExtensionWarning
    };
}

/**
 * Renderer-safe logger that doesn't use Node.js APIs.
 * Logs to console and can optionally send logs to main process via IPC.
 */

export enum LogLevel {
    DEBUG = 0,
    INFO = 1,
    WARN = 2,
    ERROR = 3
}

type LogData = string | number | boolean | object | null | undefined | Error;

class RendererLogger {
    private currentLevel: LogLevel = LogLevel.INFO;

    setLevel(level: LogLevel): void {
        this.currentLevel = level;
    }

    getLevel(): LogLevel {
        return this.currentLevel;
    }

    debug(context: string, message: string, data?: LogData): void {
        if (this.currentLevel <= LogLevel.DEBUG) {
            this.log(LogLevel.DEBUG, context, message, data);
        }
    }

    info(context: string, message: string, data?: LogData): void {
        if (this.currentLevel <= LogLevel.INFO) {
            this.log(LogLevel.INFO, context, message, data);
        }
    }

    warn(context: string, message: string, data?: LogData): void {
        if (this.currentLevel <= LogLevel.WARN) {
            this.log(LogLevel.WARN, context, message, data);
        }
    }

    error(context: string, message: string, data?: LogData): void {
        if (this.currentLevel <= LogLevel.ERROR) {
            this.log(LogLevel.ERROR, context, message, data);
        }
    }

    private log(level: LogLevel, context: string, message: string, data?: LogData): void {
        const timestamp = new Date().toISOString();
        const levelStr = LogLevel[level];
        const formattedMessage = `[${timestamp}] [${levelStr}] [${context}] ${message}`;

        const consoleMethod = this.getConsoleMethod(level);
        if (data !== undefined) {
            consoleMethod(formattedMessage, data);
        } else {
            consoleMethod(formattedMessage);
        }
    }

    private getConsoleMethod(level: LogLevel): (...args: unknown[]) => void {
        switch (level) {
            case LogLevel.DEBUG:
                return console.debug.bind(console);
            case LogLevel.INFO:
                return console.info.bind(console);
            case LogLevel.WARN:
                return console.warn.bind(console);
            case LogLevel.ERROR:
                return console.error.bind(console);
            default:
                return console.log.bind(console);
        }
    }
}

export const appLogger = new RendererLogger();
